INSERT INTO `opland_imputaciones` (`id`, `nombre`, `fecha_imputacion`, `duracion`, `no_facturable`, `id_tareas`, `observacion`, `id_presupuestos`, `control_user`, `createuser`, `updateuser`, `createdat`, `updatedat`, `factura_opland`, `factura_pago_interna`, `id_fta_soportadas`, `file_imagen`, `deleted`, `fecha_contable`) VALUES
(1, 'Detectar y quitar duplicado de la tabla clientes', '2021-10-14', '00:30:00', 0, 76, NULL, NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-10-14'),
(2, 'Quitar CHAR(10) y CHAR(13) de Nombre, NombreLF, Direccion...', '2021-10-14', '00:45:00', 0, 76, NULL, NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-10-14'),
(3, 'Detectar y quitar CHAR(10) y CHAR(13) de Nombre, NombreLF, Direccion...', '2021-09-29', '02:00:00', 0, 76, '<p>UPDATE [diTPV].[dbo].[Clientes] SET Nombre = REPLACE(REPLACE(Nombre, CHAR(13),\'\'),CHAR(10),\'\');<br>UPDATE [diTPV].[dbo].[Clientes] SET NombreLF = REPLACE(REPLACE(NombreLF, CHAR(13),\'\'),CHAR(10),\'\');<br>UPDATE [diTPV].[dbo].[Clientes] SET NIF = REPLACE(REPLACE(NIF, CHAR(13),\'\'),CHAR(10),\'\');<br>UPDATE [diTPV].[dbo].[Clientes] SET Poblacion = REPLACE(REPLACE(Poblacion, CHAR(13),\'\'),CHAR(10),\'\');<br>UPDATE [diTPV].[dbo].[Clientes] SET Provincia = REPLACE(REPLACE(Provincia, CHAR(13),\'\'),CHAR(10),\'\');<br>UPDATE [diTPV].[dbo].[Clientes] SET Pais = REPLACE(REPLACE(Pais, CHAR(13),\'\'),CHAR(10),\'\');<br>UPDATE [diTPV].[dbo].[Clientes] SET CodPostal = REPLACE(REPLACE(CodPostal, CHAR(13),\'\'),CHAR(10),\'\');</p>', NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-09-29'),
(4, 'Presentación PBI', '2021-10-14', '02:00:00', 0, 79, NULL, NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-10-14'),
(5, 'Inserción datos en TPV', '2021-10-17', '00:45:00', 0, 80, '<p>Prueba de emisión de facturas PF (x)</p><p>Cierre de caja</p><p>Observaciones de líneas</p><p>Fecha de movimientos de caja (x)</p><p>Cuadre de caja</p>', NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-10-17'),
(6, 'Inserción datos y cálculo deuda acumulada', '2021-10-18', '02:00:00', 0, 80, NULL, NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-10-18'),
(7, 'Modelo de datos y esquema PBI', '2021-10-18', '02:30:00', 0, 81, NULL, NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-10-18'),
(8, 'Vídeo tutorial', '2021-10-19', '01:00:00', 0, 82, NULL, NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-10-19'),
(9, 'Modificacion jornadas', '2021-11-22', '01:00:00', 0, 100, '<p>Ya está cambiado el formato horas, el abrir solo funciona desde la descripción, se han ocultado las columnas createuser y updateuser y en la vista movil ya se ve la fecha inicio y la de fin</p>', NULL, 18, 1, 11, NULL, '2024-12-08 19:22:02', NULL, 'Compensación socios 2022', NULL, NULL, 0, '2021-11-22'),
(10, 'Cañonazo', '2021-11-24', '00:15:00', 0, 105, '<p>UPDATE u323365229_opland.fitness_contratos<br>SET nombre=\'Verde\' where id_grupo=1;</p><p>UPDATE u323365229_opland.fitness_contratos<br>SET nombre=\'Azul\' where id_grupo=2;</p><p>UPDATE u323365229_opland.fitness_contratos<br>SET nombre=\'Rojo\' where id_grupo=3;</p><p>UPDATE u323365229_opland.fitness_contratos<br>SET nombre=\'Amarillo\' where id_grupo=6;</p><p>UPDATE u323365229_opland.fitness_contratos<br>SET nombre=\'Naranja\' where id_grupo=7;</p><p>UPDATE u323365229_opland.fitness_contratos<br>SET nombre=\'Consulta\' where id_grupo=8;</p><p>UPDATE u323365229_opland.fitness_contratos<br>SET nombre=\'Otros\' where id_grupo=9;</p>', NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-11-24'),
(11, 'Quitar tildes de los nombres de artículos para facilitar búsqueda.', '2021-12-01', '01:00:00', 0, 76, '<p>UPDATE [diTPV].[dbo].[Articulos] SET Articulo=REPLACE(Articulo,\'Á\',\'A\');<br>UPDATE [diTPV].[dbo].[Articulos] SET Articulo=REPLACE(Articulo,\'É\',\'E\');<br>UPDATE [diTPV].[dbo].[Articulos] SET Articulo=REPLACE(Articulo,\'Í\',\'I\');<br>UPDATE [diTPV].[dbo].[Articulos] SET Articulo=REPLACE(Articulo,\'Ó\',\'O\');<br>UPDATE [diTPV].[dbo].[Articulos] SET Articulo=REPLACE(Articulo,\'Ú\',\'U\');<br>UPDATE [diTPV].[dbo].[Articulos] SET Articulo=REPLACE(Articulo,\'À\',\'A\');<br>UPDATE [diTPV].[dbo].[Articulos] SET Articulo=REPLACE(Articulo,\'È\',\'E\');<br>UPDATE [diTPV].[dbo].[Articulos] SET Articulo=REPLACE(Articulo,\'Ò\',\'O\');</p>', NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-12-01'),
(12, 'Summarize líneas albaranes proveedor mismo artículo', '2021-12-08', '01:30:00', 0, 107, '<p>En un albarán vienen varias líneas de un mismo artículo, bien porque regalan algunas unidades, bien porque viene en varias piezas. Esto es considerado como distintas compras, además de afectar al cálculo del coste promedio (el precio se mantiene pero se añade un dto del 100%).</p>', NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-12-08'),
(13, 'Summarize ventas mismo artículo', '2021-12-09', '04:00:00', 0, 107, '<p>Una venta desde el TPV tiene varias líneas para un mismo artículo si se hace un descuento → Para obtener el precio real de venta es necesario agrupar estas filas. También se hace para los albaranes por si sucediera algo parecido.</p>', NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-12-09'),
(14, 'Summarizes --> problemas con TOPN', '2021-12-09', '03:00:00', 0, 107, '<p>La función TOPN para el último precio de compra estaba devolviendo más de una línea por el criterio de ordenación</p>', NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-12-09'),
(15, 'Inserción de periodos', '2021-12-12', '01:00:00', 0, 107, '<p>Insertar tabla períodos: hoy, ayer, últimos X días…</p>', NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-12-12'),
(16, 'Vista ventas totales: tiques + albaranes', '2021-12-12', '02:00:00', 0, 107, NULL, NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-12-12'),
(17, 'Revisión datos', '2021-12-12', '02:00:00', 0, 107, '<p>Se están comprando la “Paleta Maquina Naval 100Gr” a 60€ y se está vendiendo a 10€</p>', NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-12-12'),
(18, 'Creación cuadros de mandos', '2022-05-01', '08:00:00', 0, 163, NULL, NULL, 11, 11, 11, NULL, '2024-12-08 19:42:05', NULL, 'Compensación socios 2022', NULL, NULL, 0, '2022-05-01'),
(19, 'Unir tablas de líneas', '2021-12-14', '03:00:00', 0, 107, NULL, NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-12-14'),
