(22, 'Cabeceras y lineas ventas', '2021-12-17', '02:00:00', 0, 107, NULL, NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-12-17'),
(23, 'Validación', '2021-12-18', '02:00:00', 0, 108, NULL, NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-12-18'),
(24, 'Función para la carga de sucesivas llamadas a la API', '2021-12-30', '03:00:00', 0, 110, '<p>let<br>&nbsp;&nbsp;&nbsp;&nbsp;Origen = (Tabla) =&gt; let<br>&nbsp;&nbsp;&nbsp;&nbsp;#\"Llamadas\" = List.Generate(<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;()&nbsp; =&gt;&nbsp; [ Offset = 1, registros = fnNumFilasFact(Tabla, 1) ],<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;each [registros]&gt;0,<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;each [Offset =&nbsp; [Offset] + 1, registros = fnNumFilasFact( Tabla, [Offset]+1 )],<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;each [Offset]<br>&nbsp;),<br>&nbsp;&nbsp;&nbsp;&nbsp;#\"Convertida en tabla\" = Table.FromList(Llamadas, Splitter.SplitByNothing(), null, null, ExtraValues.Error),<br>&nbsp;&nbsp;&nbsp;&nbsp;#\"Columnas con nombre cambiado\" = Table.RenameColumns(#\"Convertida en tabla\",{{\"Column1\", \"Llamadas\"}}),<br>&nbsp;&nbsp;&nbsp;&nbsp;#\"Tipo cambiado\" = Table.TransformColumnTypes(#\"Columnas con nombre cambiado\",{{\"Llamadas\", type text}}),<br>SearchSuccessful = (Llamadas) =&gt;<br>let<br>&nbsp;&nbsp;&nbsp;&nbsp;Origen = Json.Document(Web.Contents(\"<a href=\"https://smart.aeolservice.es/api/getInfo2/GFGUILLEM1/\">https://smart.aeolservice.es/api/getInfo2/GFGUILLEM1/</a>\"&amp;Tabla&amp;\"/\"&amp;Llamadas, [Headers=[#\"X-Auth-Token\"=\"DivpoKTsHYWiITS1pk4NlrE18iBvJ3W0D5XbwEeB\"]])),<br>&nbsp;&nbsp;&nbsp;&nbsp;#\"Convertido en tabla\" = Record.ToTable(Origen),<br>&nbsp;&nbsp;&nbsp;&nbsp;#\"Filas filtradas1\" = Table.SelectRows(#\"Convertido en tabla\", each ([Name] = \"values\")),<br>&nbsp;&nbsp;&nbsp;&nbsp;#\"Otras columnas quitadas\" = Table.SelectColumns(#\"Filas filtradas1\",{\"Value\"}),<br>&nbsp;&nbsp;&nbsp;&nbsp;#\"Se expandió Value\" = Table.ExpandListColumn(#\"Otras columnas quitadas\", \"Value\")<br>in<br>&nbsp;&nbsp;&nbsp;&nbsp;#\"Se expandió Value\",<br>Output = Table.AddColumn(#\"Tipo cambiado\",\"Column1\",each SearchSuccessful([Llamadas])),<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;#\"Se expandió Column1\" = Table.ExpandTableColumn(Output, \"Column1\", {\"Value\"}, {\"Value\"})<br>in<br>&nbsp;&nbsp;&nbsp;&nbsp;#\"Se expandió Column1\"<br>in<br>&nbsp;&nbsp;&nbsp;&nbsp;Origen</p>', NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-12-30'),
(25, 'Función para definir número de registros de una tabla', '2021-12-30', '02:00:00', 0, 110, '<p>Función <strong>fnNumFilasFact:</strong><br>let<br>&nbsp;&nbsp;&nbsp;&nbsp;Origen = (Tabla,Offset) =&gt; let<br>&nbsp;&nbsp;&nbsp;&nbsp;Origen = Json.Document(Web.Contents(\"<a href=\"https://smart.aeolservice.es/api/getInfo2/GFGUILLEM1/\">https://smart.aeolservice.es/api/getInfo2/GFGUILLEM1/</a>\"&amp;Tabla&amp;\"/\"&amp; Number.ToText( Offset )<br>&nbsp;&nbsp;&nbsp;&nbsp;, [Headers=[#\"X-Auth-Token\"=\"DivpoKTsHYWiITS1pk4NlrE18iBvJ3W0D5XbwEeB\"]]))[values],<br>&nbsp;&nbsp;&nbsp;&nbsp;#\"Recuento calculado\" = List.NonNullCount(Origen)<br>in<br>&nbsp;&nbsp;&nbsp;&nbsp;#\"Recuento calculado\"<br>in<br>&nbsp;&nbsp;&nbsp;&nbsp;Origen</p>', NULL, 11, 11, 11, NULL, '2024-12-08 19:22:30', NULL, 'Dividendos 2022', NULL, NULL, 0, '2021-12-30'),
