INSERT INTO `opland_insight` (`id`, `nombre`, `comentario`, `link`, `file_file`, `tags_tag`) VALUES
(1, 'How to return 0 instead of BLANK in DAX', NULL, 'https://www.sqlbi.com/articles/how-to-return-0-instead-of-blank-in-dax/', 'opland/insight/ud5V6kfaMcxCboQJ3fLkjlZVVgitdaypI70wmqsS.png', 'DAX'),
(2, 'Recuperar último registro de otra tabla', '<p>Ultimo comentario management =</p><p>var fecha=CALCULATE(MAX(poseidon_comments[createdat]))</p><p>return</p><p>CALCULATE(LASTNONBLANK(poseidon_comments[nombre],TRUE()),FILTER(poseidon_comments,poseidon[id]=poseidon_comments[id_poseidon] &amp;&amp; poseidon_comments[createdat]=fecha))</p>', NULL, NULL, 'DAX'),
(3, 'Editar archivos php y css en página login', '<p><strong>1.- Eliminar fondo gris detrás de los logos de proyecto:</strong></p><p>/public_html/public/resources/views/basic/proyectos.blade.php&nbsp;</p><p>/public_html/public/resources/views/basic/layouts/menus -→ menu_basic.blade.php</p><p>Quité background-color: #cdcdcd dentro de style{} a continuación del nombre de la foto&nbsp;</p><p><strong>2.- Introducir logos de proyectos:</strong></p><p>/public_html/public/assets</p><p>Crear carpeta con el nombre del proyecto</p><p>Meter un archivo png y nombrarlo con el nombre del proyecto en minúsculas y “_logo.png”&nbsp;</p><p><strong>3.- Cambiar imagen de fondo:</strong></p><p>/public_html/public/assets/basic/images/pages</p><p>Subir el archivo que queramos meter en el fondo y nombrarlo como “paper-opland.jpg”</p><p><strong>4.- Cambiar el logo de Opland en la pantalla de login sobre los inputs:</strong></p><p>La imagen está en /public_html/public/assets/basic/images y el archivo se llama isotipo-opland-azul.png</p><p>/public_html/resources/views/basic/login.blade.php</p><p>style=\"width: 80px;height: 80px;\"&gt; en lugar de 50px por 50 px que me parecía muy pequeño. Dejamos dimensiones absolutas porque cuadra bien tanto en monitor como en móvil.</p><p><strong>5.- Cambiar el logo de Opland sobre el fondo de la pantalla de login:</strong></p><p>La imagen está en /public_html/public/assets/basic/images y se nombra como “opland-logo-blanco.png”.</p><p>/public_html/resources/views/basic/login.blade.php</p><p>Pongo width: 780px a continuación de la ruta de la imagen y como en bootstrap.ccs:501 (bootstrap.css línea 501) pone .img-fluid {max-width: 100%; height: auto;}, se adapta a ese ancho como máximo y si se reduce el tamaño de la pantalla se reduce el tamaño de la imagen.<br><br><strong>6.- Modificar formato de Usuario y Password en la pantalla de login:</strong></p><p>/public_html/resources/views/basic/login.blade.php</p><p>Añado class=\"form-label\" antes de \"Password\" como está puesto antes de \"Usuario\" para que tengan el mismo tamaño de letra, el mismo margen y el mismo grosor de letra.</p><p>/public_html/public/assets/basic/css/boostrap.css (línea 1650)</p><p>.form-label {<br>&nbsp; margin-bottom: 0.1rem; /* He quitado margin-bottom: 0.2857rem */<br>&nbsp; font-size: 1.1rem; /* He quitado font-size: 0.857rem; */<br>&nbsp; font-weight:600;<br>&nbsp;color: #5e5873; }</p>', NULL, NULL, 'PHP,CSS,LOGIN'),
(4, 'php y Xampp: virtual host', '<p><a href=\"https://www.youtube.com/watch?v=laXc22YPGhg&amp;list=PLZ2ovOgdI-kVtF2yQ2kiZetWWTmOQoUSG&amp;index=6\">https://www.youtube.com/watch?v=laXc22YPGhg&amp;list=PLZ2ovOgdI-kVtF2yQ2kiZetWWTmOQoUSG&amp;index=6</a></p><p>Minuto 23</p>', 'https://www.youtube.com/watch?v=laXc22YPGhg&list=PLZ2ovOgdI-kVtF2yQ2kiZetWWTmOQoUSG&index=6', NULL, NULL);
INSERT INTO `opland_manual` (`id`, `nombre`, `descripcion`, `comentarios`, `createuser`, `updateuser`, `createdat`, `updatedat`) VALUES
(1, '01.- Creación de proyecto', '<p>Si el usuario desea crear un nuevo proyecto debe clicar en [+ Crear Proyecto] e indicar el nombre del proyecto.</p>', '<p>Ahora mismo cuando pones el proyecto con un espacio te lo junta todo, me parece bien para la BD pero no para la interfaz. ¿Se puede solucionar?</p><p>¿Se puede poner un nombre de proyecto con espacios que luego se guarde en base de datos con guiones bajos? Eso es algo básico para UX.</p>', 18, 18, '2023-11-02 16:33:33', '2023-11-02 16:46:37'),
(2, '02.- Acceso a proyecto', '<p>Clicando sobre [Seleccionar Proyecto], el usuario puede acceder a cualquiera de los proyectos sobre los que se le hayan asignado permisos.</p><p>Al entrar en el proyecto se accede a la sección “Panel”.</p>', NULL, 18, 18, '2023-11-02 16:34:58', '2023-11-02 16:46:48'),
(3, '03.- Panel / Ajustes', '<p>Al entrar en un proyecto, el usuario accede a la sección Panel, en ella encontrará las tablas que no se hayan marcado como submenú en la tabla Configuración y el botón de acceso al Cuadro de mandos.</p><p>Clicando sobre el menú Opland (logo opland en la parte superior derecha de la pantalla), aparece un desplegable con las siguientes opciones:</p><ul><li>Perfil: En esta sección el usuario puede modificar sus datos personales y su contraseña.</li><li>Ajustes: En esta sección el usuario puede ver las tablas marcadas como submenú en la tabla “Configuración”.</li><li>Administración: Los usuarios administradores tienen acceso a las tablas de configuración avanzada de cada uno de los proyectos.</li><li>Proyectos: El usuario puede volver al menú de proyectos clicando en esta opción del menú.</li><li>Editar proyectos: En esta sección el usuario puede editar y crear tablas.</li><li>Cerrar sesión: El usuario puede desloguearse clicando esta opción.</li></ul>', NULL, 18, 18, '2023-11-02 16:46:10', '2023-11-02 17:30:16'),
(4, '04.- Tabla Configuración', '<p>La tabla de configuración del proyecto cuenta con los siguientes campos por defecto:</p><ul><li>Submenú: Permite llevar tablas (diccionarios, configuración, manual, roles, etc…) de Panel a Ajustes.</li><li>Filters:</li><li>Deletes: Activa el botón Borrar en el menú de fila de una tabla.</li><li>Main_filter: Permite indicar qué tabla aporta los valores con los que filtrar las tablas que se vean afectadas por el filtro.</li><li>Guardar: Permite incluir acciones adicionales además de Guardar. Las opciones adicionales disponibles son nuevo (volver y nuevo), volver (guardar y volver) y continuar (guardar y continuar).</li><li>Inicio: Permite indicar qué tabla quiere ver nada más acceder al proyecto.</li></ul>', NULL, 18, 2, '2023-11-02 17:34:32', '2023-11-09 17:40:17'),
(5, '05.- Creación de nueva tabla', '<p>El usuario puede Editar Proyecto desplegando el menú representado por el icono de Opland en la parte superior derecha de la pantalla.</p><p>El menú de edición de proyecto muestra las tablas de la sección Ajustes a la izquierda, las tablas a editar/borrar del proyecto en la parte superior y la tabla a crear en la parte inferior.</p><p>Para crear una nueva tabla, el usuario solo tiene que poner el nombre de la nueva tabla y apretar a “Crear tabla”.</p>', NULL, 2, 2, '2023-11-09 17:41:24', '2023-11-12 20:25:41'),
(6, '06.- Edición de tabla - Campos disponibles.', NULL, NULL, 2, 2, '2023-11-12 20:26:08', '2023-11-12 20:26:08');
