(2, 'Datos acceso a LF', '<p>AnyDesk LF1: 410099347</p><p>AnyDesk LF2: 710814902</p><p>Pass (Idrica): Capellanes23!</p><p>&nbsp;</p>', NULL, 11, 11, '2023-01-10 08:47:34', '2024-01-10 18:03:18'),
(3, 'Generación de tokens', '<p><a href=\"https://desarrollos.opland.es/api/generateToken/dugarse\">https://desarrollos.opland.es/api/generateToken/dugarse</a></p><p>{\"token\":\"d6169a40660434b07a4f24a2351d5c432e28b8ed3516919d6213534fa4ddf782\",\"plainTextToken\":\"XyW4T6GLfvrzhTzFQxZhnhq87yaswOGWfZ0XMi1k\"}</p>', NULL, 11, 11, '2023-01-27 14:09:09', '2023-02-21 08:21:19'),
(4, 'Acceso PBI Opland', '<p>Onomatopeya00204</p>', NULL, 2, 11, '2023-04-26 19:53:03', '2023-10-14 14:56:48'),
(5, 'Query Opland acceso usuarios', '<p>SELECT email, MAX(timestamp) as \'UltimaCon\' ,COUNT(*) as \'Num\' FROM `admin_accesos` a<br>join `users` u on u.id=a.id_users<br>GROUP BY u.email<br>ORDER by MAX(timestamp) DESC</p>', NULL, 11, 11, '2023-05-15 09:45:46', '2023-05-15 09:45:46'),
(6, 'Modificación formato fecha en Power Query', '<p>= Table.TransformColumns(Origen, {{\"Fecha operación\", each Text.Combine({Date.ToText(_, \"yyyy\"), \"-\", Date.ToText(_, \"MM\"), \"-\", Date.ToText(_, \"dd\")})}})</p>', NULL, 11, 11, '2023-10-14 14:57:16', '2023-10-14 14:57:16'),
(7, 'Correos cuentas @opland.es', '<p>lacarniceriagallega@opland.es, OPlandCG21!<br>naturefitness@opland.es, OPlandNF21!<br>lafreshquita@opland.es, OPlandLF22!</p>', NULL, 11, 11, '2023-10-25 07:58:18', '2023-10-25 07:58:18'),
(8, 'API Power Query', '<p>let<br>&nbsp; &nbsp;Listado = List.Generate( &nbsp;<br>&nbsp; &nbsp; () &nbsp;=&gt; &nbsp;[ step = 1, Origen = Json.Document(Web.Contents(\"https://desarrollos.opland.es/api/get2/proyecto/tabla/\"<br>&nbsp; &nbsp; &nbsp; &nbsp;, [Headers=[#\"X-Auth-Token\"=\"sdVl4aQdV8dJgBD0OkCZdgtes2DFlV\", page =Number.ToText(step)]]))[values]],<br>&nbsp; &nbsp; each List.Count([Origen])&gt;0,<br>&nbsp; &nbsp; each [step = &nbsp;[step] + 1, Origen = Json.Document(Web.Contents(\"https://desarrollos.opland.es/api/get2/proyecto/tabla/\"<br>&nbsp; &nbsp; &nbsp; &nbsp;, [Headers=[#\"X-Auth-Token\"=\"sdVl4aQdV8dJgBD0OkCZdgtes2xeJqAB9y8PDFlV\", page =Number.ToText(step)]]))[values]]<br>),<br>&nbsp; &nbsp;#\"Convertida en tabla\" = Table.FromList(Listado, Splitter.SplitByNothing(), null, null, ExtraValues.Error),<br>&nbsp; &nbsp;#\"Se expandió Column1\" = Table.ExpandRecordColumn(#\"Convertida en tabla\", \"Column1\", {\"step\", \"Origen\"}, {\"step\", \"Origen\"}),<br>&nbsp; &nbsp;#\"Columnas quitadas\" = Table.RemoveColumns(#\"Se expandió Column1\",{\"step\"}),<br>&nbsp; &nbsp;#\"Se expandió Origen\" = Table.ExpandListColumn(#\"Columnas quitadas\", \"Origen\")<br>in<br>&nbsp; &nbsp;#\"Se expandió Origen\"</p>', NULL, 11, 11, '2023-10-27 17:17:16', '2023-11-15 06:37:43'),
(9, 'Power Query: listado de tablas', '<p>let<br>&nbsp; &nbsp;url = \"https://gestion.opland.es/api/get2/dugarse\",<br>&nbsp; &nbsp;Origen = List.Generate(<br>&nbsp; &nbsp; &nbsp; &nbsp;()=&gt;[x = 2, Result = Json.Document(Web.Contents(url, [Headers=[#\"X-Auth-Token\"=\"Mlx1TPT5xJO2oa2eWXqiR\"]]))],<br>&nbsp; &nbsp;each List.Count([Result][tables]) &lt;&gt; 1,<br>&nbsp; &nbsp;each [x=[x]+1,Result = Json.Document(Web.Contents(Text.Combine({url, Number.ToText([x])}), [Headers=[#\"X-Auth-Token\"=\"Mlx1TiGiKtYNO4N1CqLalXaEPT5xJO2oa2eWXqiR\"]]))]<br>&nbsp; &nbsp;),<br>&nbsp; &nbsp;Origen1 = Origen{0},<br>&nbsp; &nbsp;Result = Origen1[Result],<br>&nbsp; &nbsp;tables = Result[tables]<br>in<br>&nbsp; &nbsp;tables</p>', NULL, 11, 11, '2023-10-29 06:43:58', '2023-10-29 06:44:11'),
(10, 'API sencilla Power Query', '<p>let<br>&nbsp; &nbsp;Origen = Json.Document(Web.Contents(\"https://desarrollos.opland.es/api/get2/fitness_prod/grupo\", [Headers=[#\"X-Auth-Token\"=\"9TDUv9pAyzN7CXP91UXEfFa6oxA8j\"]])),<br>&nbsp; &nbsp;#\"Convertido en tabla\" = Record.ToTable(Origen),<br>&nbsp; &nbsp;#\"Filas filtradas\" = Table.SelectRows(#\"Convertido en tabla\", each ([Name] = \"values\")),<br>&nbsp; &nbsp;#\"Se expandió Value\" = Table.ExpandListColumn(#\"Filas filtradas\", \"Value\"),<br>&nbsp; &nbsp;#\"Se expandió Value1\" = Table.ExpandRecordColumn(#\"Se expandió Value\", \"Value\", {\"id\", \"nombre\", \"descripcion\", \"id_tipo\"}, {\"id\", \"nombre\", \"descripcion\", \"id_tipo\"}),<br>&nbsp; &nbsp;#\"Columnas quitadas\" = Table.RemoveColumns(#\"Se expandió Value1\",{\"Name\"}),<br>&nbsp; &nbsp;#\"Personalizada agregada\" = Table.AddColumn(#\"Columnas quitadas\", \"URL\", each \"https://gestion.opland.es/editar/fitness/grupo/\" &amp; Text.From([id]))<br>in<br>&nbsp; &nbsp;#\"Personalizada agregada\"</p>', NULL, 11, 11, '2023-10-29 07:08:57', '2023-10-29 07:08:57'),
(11, 'Conexiones Opland', '<p><strong>FTP PRO</strong></p><p>ftp.gestion.opland.es<br>u323365229.tomas<br>u6ghutdJI8</p><p><strong>FTP DESA</strong></p><p>185.166.188.52<br>u323365229.desarrollos.opland.es.tomas<br>QDdXUiN5bkA2VVhy</p><p><strong>BBDD PRO</strong></p><p>https://auth-db780.hstgr.io/index.php?route=/<br>u323365229_opland<br>YGue@6Iu</p><p><strong>BBDD DESA</strong></p><p>https://auth-db780.hstgr.io/index.php?route=/<br>u342962294_NZMAO<br>YGue@6Iu</p><p><strong>BBDD PRE</strong></p><p>BBDD: u342962294_oplandpre<br>User: u342962294_oplandpre<br>PWD: Y*uc!Bd=0</p><p>&nbsp;</p><p>&nbsp;</p>', NULL, 11, 11, '2023-11-05 15:13:28', '2023-11-05 15:13:28'),
(12, 'Power Query: modificar datos en una columna en función del valor de otra', '<p>= Table.ReplaceValue(#\"Personalizada agregada\", each [nombre], each if [deleted] = 1 then Text.Combine({\"ι \", [nombre]}) else [nombre],Replacer.ReplaceValue,{\"nombre\"})</p>', NULL, 11, 11, '2023-11-06 16:16:46', '2023-11-06 16:16:46'),
(13, 'Tokens proyectos', '<p>Opland: sdVl4aQdV8dJgBD0OkCZdgtes2xeJqAB9y8PDFlV</p><p>Qatium: sdVl4aQdV8dJgBD0OkCZdgtes2xeJqAB9y8PDFlV</p><p>N&amp;F: 9TDUv9pAyzN7CXP91UXEfFa6ox3dWdCkmB9h0A8j</p><p>ORL: WmIp61s3LxT3rWMVdWIlR2R7V24CGCgZYh58yPsd</p><p>Dysama: DJFclXhwtLMZVv02hBLs8t4SCo3QueLsye648YyJ</p>', NULL, 11, 11, '2023-11-15 06:40:34', '2024-06-19 08:06:45'),
(17, 'Duplicar facturas de Opland (las que estén como NO ARCHIVADAS)', '<p>-- Obtener la fecha actual y el año actual<br>SET @fecha_actual = CURDATE();<br>SET @año_actual = YEAR(@fecha_actual);</p><p>-- Obtener el mayor número de factura actual<br>SET @max_num_fact = (<br>&nbsp; &nbsp;SELECT IFNULL(MAX(CAST(SUBSTRING_INDEX(num_fact, \'/\', -1) AS UNSIGNED)), 0)<br>&nbsp; &nbsp;FROM opland_facturas<br>&nbsp; &nbsp;WHERE num_fact LIKE CONCAT(@año_actual, \'/%\')<br>);</p><p>-- Preparar la tabla temporal para mapear los IDs de las facturas duplicadas<br>DROP TEMPORARY TABLE IF EXISTS temp_facturas;<br>CREATE TEMPORARY TABLE temp_facturas (<br>&nbsp; &nbsp;old_id INT,<br>&nbsp; &nbsp;new_id INT<br>);</p><p>-- Duplicar las facturas que no están marcadas como deleted<br>INSERT INTO opland_facturas (<br>&nbsp; &nbsp;nombre,<br>&nbsp; &nbsp;num_fact,<br>&nbsp; &nbsp;descripcion,<br>&nbsp; &nbsp;fecha_emision,<br>&nbsp; &nbsp;id_clientes,<br>&nbsp; &nbsp;dtototae,<br>&nbsp; &nbsp;dtototalporc,<br>&nbsp; &nbsp;IVA,<br>&nbsp; &nbsp;id_proyectos,<br>&nbsp; &nbsp;base_imponible,<br>&nbsp; &nbsp;total_a_pagar,<br>&nbsp; &nbsp;incobrable<br>)<br>SELECT&nbsp;<br>&nbsp; &nbsp;CONCAT(CONCAT(@año_actual, \'/\', @max_num_fact + (@rownum := @rownum + 1)), \' - \', descripcion) AS nombre,<br>&nbsp; &nbsp;CONCAT(@año_actual, \'/\', @max_num_fact + @rownum) AS num_fact,<br>&nbsp; &nbsp;descripcion,<br>&nbsp; &nbsp;@fecha_actual AS fecha_emision,<br>&nbsp; &nbsp;id_clientes,<br>&nbsp; &nbsp;dtototae,<br>&nbsp; &nbsp;dtototalporc,<br>&nbsp; &nbsp;IVA,<br>&nbsp; &nbsp;id_proyectos,<br>&nbsp; &nbsp;base_imponible,<br>&nbsp; &nbsp;total_a_pagar,<br>&nbsp; &nbsp;incobrable<br>FROM opland_facturas, (SELECT @rownum := 0) r<br>WHERE deleted = 0;</p><p>-- Mapear los IDs de las facturas originales a las duplicadas<br>INSERT INTO temp_facturas (old_id, new_id)<br>SELECT old.id, new.id<br>FROM opland_facturas old<br>JOIN opland_facturas new<br>ON old.deleted = 0<br>AND new.fecha_emision = @fecha_actual<br>AND old.descripcion = new.descripcion;</p><p>-- Duplicar los conceptos de las facturas duplicadas<br>INSERT INTO opland_concepto_factura (<br>&nbsp; &nbsp;nombre,<br>&nbsp; &nbsp;id_facturas,<br>&nbsp; &nbsp;precio,<br>&nbsp; &nbsp;descuentoe,<br>&nbsp; &nbsp;id_conceptos,<br>&nbsp; &nbsp;descuentoporc<br>)<br>SELECT&nbsp;<br>&nbsp; &nbsp;ocf.nombre,<br>&nbsp; &nbsp;tf.new_id AS nueva_factura_id,<br>&nbsp; &nbsp;ocf.precio,<br>&nbsp; &nbsp;ocf.descuentoe,<br>&nbsp; &nbsp;ocf.id_conceptos,<br>&nbsp; &nbsp;ocf.descuentoporc<br>FROM opland_concepto_factura ocf<br>JOIN temp_facturas tf<br>ON ocf.id_facturas = tf.old_id;</p><p>-- Limpiar la tabla temporal<br>DROP TEMPORARY TABLE IF EXISTS temp_facturas;</p>', NULL, 11, 11, '2024-07-04 21:40:23', '2024-07-04 21:40:23'),
(18, 'Servidores', '<p>Desarrollo:<br>https://auth-db780.hstgr.io/index.php?route=/<br>u342962294_NZMAO<br>YGue@6Iu</p><p>Gestion:<br>https://auth-db780.hstgr.io/index.php?route=/<br>u323365229_opland<br>YGue@6Iu</p>', NULL, 11, 11, '2026-02-17 11:36:07', '2026-02-17 11:36:07'),
(19, 'OVH', '<p>user: <a href=\"mailto:trodriguez@opland.es\">trodriguez@opland.es</a></p><p>pass: Apavital.2025!</p><p>Azure DB: Tomas2026</p><p>Pass Ubuntu: TSgl@1315</p><p>Pass Postgres: USER opland WITH PASSWORD \'D3Aki4lC!el0\'; <strong>opland1234</strong></p><p>GitHub: <a href=\"mailto:trodriguez@opland.es\">trodriguez@opland.es</a> pass Apavital.2025!</p><h2>Guía: Migración de Azure a OVHcloud con Laravel + PostgreSQL</h2><h2>Resumen del setup</h2><ul><li><strong>Proveedor</strong>: OVHcloud</li><li><strong>Servidor</strong>: VPS-1 (4 vCPU, 8GB RAM, 75GB SSD)</li><li><strong>Ubicación</strong>: Frankfurt DE2 (Alemania)</li><li><strong>IP</strong>: 141.95.51.71</li><li><strong>SO</strong>: Ubuntu 22.04 LTS</li><li><strong>Stack</strong>: Laravel + PHP 8.2 + Nginx + PostgreSQL</li></ul><h3>1. Contratar el VPS en OVHcloud</h3><ol><li>Ir a <a href=\"https://ovhcloud.com/es-es\">ovhcloud.com/es-es</a></li><li>Menú → <strong>Servidores dedicados y VPS</strong> → <strong>VPS</strong></li><li>Seleccionar <strong>VPS-1</strong> (o superior si se necesita más potencia)</li><li>Elegir <strong>Ubuntu 22.04</strong> como sistema operativo</li><li>Seleccionar región (Madrid si está disponible, si no Frankfurt)</li><li>Finalizar el pedido y pagar</li></ol><h3>2. Establecer contraseña Ubuntu</h3><ol><li>Si no me mandan un mail con el enlace para restablecer la contraseña, reinstalar mi VPS desde <a href=\"https://manager.eu.ovhcloud.com/#/dedicated/vps/vps-00727187.vps.ovh.net/dashboard\">https://manager.eu.ovhcloud.com/#/dedicated/vps/vps-00727187.vps.ovh.net/dashboard</a> , bloque \"Su VPS &gt; SO/Distribución\" (avanzar hasta finalizar sin introducir nada).</li><li>Recibiré un correo con un enlace que me mostrará un secreto (contraseña de un solo uso)</li><li>Abrir PowerShell y escribir: ssh ubuntu@141.95.51.71<ol><li>Si da error de \"host identificación cambiada\" (tras reinstalar):</li><li>ssh-keygen -R 141.95.51.71</li><li>ssh ubuntu@141.95.51.71</li></ol></li><li>Introducir el secreto y luego la nueva contraseña.</li></ol><h3>3. Actualizar el sistema</h3><p>sudo apt update &amp;&amp; sudo apt upgrade -y</p><h3>4. Añadir repositorio de PHP e instalar PHP 8.2</h3><ol><li>sudo add-apt-repository ppa:ondrej/php -y &amp;&amp; sudo apt update</li><li>sudo apt install -y php8.2 php8.2-fpm php8.2-cli php8.2-pgsql php8.2-mbstring \\ &nbsp;php8.2-xml php8.2-curl php8.2-zip php8.2-bcmath php8.2-intl</li></ol><h3>5. Instalar Nginx</h3><blockquote><p>Nginx es el servidor web — el programa que recibe las visitas de los usuarios y las dirige a tu aplicación Laravel. Cuando alguien escribe tuempresa.com en el navegador, Nginx es quien responde y sirve la web. Es como el recepcionista del servidor: recibe todas las peticiones y las reparte correctamente. Sin Nginx, tu servidor no sería accesible desde internet.</p></blockquote><ol><li>sudo apt install -y nginx</li><li>sudo systemctl enable nginx</li><li>sudo systemctl start nginx</li></ol><h3>6. Instalar Composer</h3><blockquote><p>Es el gestor de dependencias de PHP — la herramienta que descarga e instala todas las librerías que necesita tu proyecto Laravel. Laravel no es un solo archivo, depende de cientos de librerías externas. Composer lee el archivo composer.json de tu proyecto y lo instala todo automáticamente con un solo comando. Es como el npm de JavaScript, pero para PHP. Si has usado npm install alguna vez, Composer es exactamente lo mismo.</p></blockquote><ol><li>curl -sS https://getcomposer.org/installer | php</li><li>sudo mv composer.phar /usr/local/bin/composer</li></ol><h3>7. Configuración de la base de datos Postgres</h3><blockquote><p><strong>Opción A</strong> — PostgreSQL gestionado en OVHcloud Public Cloud (~€15/mes)<br>Sin mantenimiento, backups automáticos, recomendado para producción.<br><strong>Opción B</strong> — PostgreSQL en el mismo VPS (gratis)<br>Más barato pero tú gestionas los backups. Válido para empezar.</p><p>Migrar de PostgreSQL local (opción B) a PostgreSQL gestionado (opción A) en el futuro es sencillo:</p><p><i>bash</i></p><p><i>pg_dump -U postgres nombre_db &gt; backup.sql psql -h host-ovhcloud -U usuario nombre_db &lt; backup.sql</i></p><p>Y cambiar una línea en el .env de Laravel con el nuevo host. En 30 minutos está hecho.</p></blockquote><ol><li>sudo apt install -y postgresql postgresql-contrib</li></ol><h3>8. Conectar con GitHub para volcar código</h3><p>Como el repositorio es privado, necesitamos darle acceso al VPS a tu repositorio privado de GitHub mediante una llave SSH. Es parecido a lo que hicimos antes.</p><p>Genera una llave SSH en el servidor:</p><p><i>bash</i></p><p><i>ssh-keygen -t ed25519 -C \"vps-ovhcloud\"</i></p><p>Pulsa Enter 3 veces (sin passphrase) y luego muestra la llave pública:</p><p><i>bash</i></p><p><i>cat ~/.ssh/id_ed25519.pub</i></p><p>Configurar el acceso desde Settings&gt;Deploy keys en GitHub</p><h3>9. Clonar respositorio Laravel</h3><ol><li>Clonar o subir el proyecto cd /var/www sudo git clone TU_REPO_URL miapp sudo chown -R ubuntu:www-data /var/www/miapp cd miapp</li><li>Instalar dependencias composer install --no-dev</li><li>Configurar entorno cp .env.example .env php artisan key:generate</li><li>Editar .env con las credenciales de PostgreSQL nano .env</li></ol><p>Valores clave en .env:</p><p>DB_CONNECTION=pgsql DB_HOST=tu-host-postgresql-ovhcloud DB_PORT=5432 DB_DATABASE=nombre_base_de_datos DB_USERNAME=usuario DB_PASSWORD=contraseña</p><h2>10. Migrar MySQL a PostgreSQL (con pgloader)</h2><p>sudo apt install -y pgloader pgloader mysql://usuario:password@host-azure/nombre_db \\ &nbsp; &nbsp; &nbsp; &nbsp; postgresql://usuario:password@host-ovhcloud/nombre_db</p><p>Ha sido problemático porque las contraseñas que había puesto en las bbdd contenían caracteres incompatibles con las instrucciones en SSH. Una vez resuelto, la complicación ha sido la conversión de MySQL a Pg. Finalmente he optado por crear manualmente las tablas en Pg porque la idea es comenzar desde cero en este nuevo servidor.</p><h2>&nbsp;</h2><h2>11. Configurar Nginx para Laravel</h2><p>sudo nano /etc/nginx/sites-available/miapp</p><p>Contenido del archivo:</p><p>server { &nbsp; &nbsp;listen 80; &nbsp; &nbsp;server_name tudominio.com www.tudominio.com; &nbsp; &nbsp;root /var/www/miapp/public; &nbsp; &nbsp;index index.php; &nbsp; &nbsp;location / { &nbsp; &nbsp; &nbsp; &nbsp;try_files $uri $uri/ /index.php?$query_string; &nbsp; &nbsp;} &nbsp; &nbsp;location ~ \\.php$ { &nbsp; &nbsp; &nbsp; &nbsp;fastcgi_pass unix:/var/run/php/php8.2-fpm.sock; &nbsp; &nbsp; &nbsp; &nbsp;fastcgi_index index.php; &nbsp; &nbsp; &nbsp; &nbsp;include fastcgi_params; &nbsp; &nbsp; &nbsp; &nbsp;fastcgi_param SCRIPT_FILENAME $realpath_root$fastcgi_script_name; &nbsp; &nbsp;} }</p><p>Activar el sitio:</p><p>sudo ln -s /etc/nginx/sites-available/miapp /etc/nginx/sites-enabled/ sudo nginx -t sudo systemctl reload nginx</p><h2>12. Instalar SSL gratuito con Let\'s Encrypt</h2><p>sudo apt install -y certbot python3-certbot-nginx sudo certbot --nginx -d tudominio.com -d www.tudominio.com</p><h2>&nbsp;</h2><p>Pasos pendientes:<br><strong>Inmediato</strong></p><ul><li>Crear las tablas en PostgreSQL con DBeaver</li><li>Migrar los datos de usuarios para poder hacer login</li><li>Probar que la app funciona correctamente</li></ul><p><strong>Antes de poner en producción</strong></p><ul><li>Configurar el dominio (apuntar tu dominio al VPS)</li><li>Instalar SSL con Let\'s Encrypt (el candado verde https://)</li><li>Cambiar APP_ENV=production y APP_DEBUG=false en el .env</li><li>Cambiar contraseña bbdd</li></ul><p><strong>Recomendable</strong></p><ul><li>Configurar backups automáticos de PostgreSQL</li><li>Cancelar el servidor de Azure una vez verificado todo</li></ul><p><strong>Opcional pero recomendado</strong></p><ul><li>Configurar el correo transaccional (Resend o Mailgun) para los emails que genera la app</li><li>Configurar un proceso para actualizar el servidor cuando hagas git push (deploy automático)</li></ul><p>&nbsp;</p><h2>Comandos útiles de mantenimiento</h2><p># Conectarse al servidor ssh ubuntu@141.95.51.71</p><p># Ver logs de Nginx sudo tail -f /var/log/nginx/error.log</p><p># Reiniciar servicios sudo systemctl restart nginx sudo systemctl restart php8.2-fpm</p><p># Ver uso de recursos htop</p><p>&nbsp;</p>', NULL, 11, 11, '2026-05-19 17:20:49', '2026-05-20 10:18:45'),
(20, 'Integración con icnea', '<p><strong>Informe Técnico — Sistema Opland / Vacation Marbella</strong></p><p><strong>Estado actual · Junio 2026</strong></p><p>&nbsp;</p><p>1. Infraestructura</p><figure class=\"table\"><table><thead><tr><th>Componente</th><th>Detalle</th></tr></thead><tbody><tr><td>Servidor</td><td>VPS OVH, Ubuntu, IP 141.95.51.71</td></tr><tr><td>Web server</td><td>Nginx</td></tr><tr><td>Framework</td><td>Laravel 8</td></tr><tr><td>Base de datos</td><td>PostgreSQL</td></tr><tr><td>Directorio app</td><td>/var/www/opland-app</td></tr><tr><td>URL producción</td><td><a href=\"https://app.opland.es/\">https://app.opland.es</a></td></tr></tbody></table></figure><p>&nbsp;</p><p>El cron del sistema ejecuta el scheduler de Laravel cada minuto:</p><p>* * * * * cd /var/www/opland-app &amp;&amp; php artisan schedule:run &gt;&gt; /dev/null 2&gt;&amp;1</p><p>&nbsp;</p><p>2. Base de datos</p><p>Motor: PostgreSQL. Las tablas de Vacation Marbella tienen el prefijo&nbsp;vacationmarbella_.</p><p>Tablas principales</p><figure class=\"table\"><table><thead><tr><th>Tabla</th><th>Descripción</th></tr></thead><tbody><tr><td>vacationmarbella_inmuebles</td><td>Catálogo de inmuebles. Campo clave:&nbsp;icnea_lodging_id&nbsp;(ID numérico Icnea) y&nbsp;icnea_code&nbsp;(acrónimo).</td></tr><tr><td>vacationmarbella_icnea_reservas</td><td>Reservas importadas desde Icnea. Campo clave:&nbsp;nombre&nbsp;(número de reserva, ej.&nbsp;R-12345). Campo de deduplicación:&nbsp;icnea_booking_ref&nbsp;(índice único parcial).</td></tr><tr><td>vacationmarbella_tareas_limpieza</td><td>Tareas de limpieza, mantenimiento y piscinas. Campo clave de deduplicación:&nbsp;icnea_booking_ref&nbsp;(índice único parcial).</td></tr></tbody></table></figure><p>&nbsp;</p><p>Índice único parcial en tareas</p><p>Para evitar duplicados en las tareas autogeneradas sin afectar a tareas manuales (que tienen&nbsp;icnea_booking_ref = NULL):</p><p>CREATE UNIQUE INDEX idx_tareas_icnea_booking_ref</p><p>ON vacationmarbella_tareas_limpieza (icnea_booking_ref)</p><p>WHERE icnea_booking_ref IS NOT NULL;</p><p>&nbsp;</p><p>3. Integración con Icnea (PMS)</p><p>Icnea es el PMS (Property Management System) que gestiona reservas, propiedades y planning. La integración se realiza vía&nbsp;<strong>SOAP</strong>&nbsp;contra el endpoint:</p><p>https://ws.icnea.net/WSserver.asmx</p><p>Credenciales de acceso:&nbsp;usr=1540,&nbsp;pwd=v$c$t$321$m$r$b</p><p>La API Icnea expone tres operaciones relevantes:</p><figure class=\"table\"><table><thead><tr><th>Operación SOAP</th><th>Uso</th></tr></thead><tbody><tr><td>Catalog</td><td>Lista completa de inmuebles con todos sus atributos</td></tr><tr><td>ControlActivitat</td><td>Registro de URL webhook para recibir notificaciones de reservas</td></tr><tr><td>Booked</td><td>Fechas ocupadas por inmueble (sin detalle de reserva)</td></tr></tbody></table></figure><p>&nbsp;</p><p><strong>Nota importante:</strong>&nbsp;La API Icnea no dispone de un endpoint para obtener el listado de reservas. El único mecanismo para recibir reservas en tiempo real es el webhook registrado vía&nbsp;ControlActivitat.</p><p>&nbsp;</p><p>4. Sincronización de inmuebles (catálogo)</p><p><strong>Comando:</strong>&nbsp;php artisan icnea:sync<br><strong>Fichero:</strong>&nbsp;app/Console/Commands/IcneaSyncCommand.php<br><strong>Frecuencia:</strong>&nbsp;Diaria a las 03:00<br><strong>Log:</strong>&nbsp;storage/logs/icnea-sync.log</p><p>Realiza una llamada SOAP&nbsp;Catalog&nbsp;que devuelve la lista completa de inmuebles Icnea. Por cada inmueble recibido, hace un UPSERT en&nbsp;vacationmarbella_inmuebles&nbsp;usando&nbsp;icnea_code&nbsp;(acrónimo) como clave de matching. Sincroniza ~80 campos (nombre, capacidad, superficies, ubicación, tarifas, fotos, etc.).</p><p><strong>Estado actual de inmuebles:</strong></p><ul><li>La mayoría de inmuebles tienen&nbsp;icnea_lodging_id&nbsp;y&nbsp;icnea_code&nbsp;correctamente asignados.</li><li>Tres inmuebles activos no tienen&nbsp;icnea_code&nbsp;y requieren matching manual: id 63 (MARBESA), id 104 (TORRE BERMEJA), id 126 (VILLA AVA).</li></ul><p>&nbsp;</p><p>5. Sincronización de reservas (webhook)</p><p>Arquitectura</p><p>Icnea notifica reservas nuevas y modificadas enviando un POST al webhook registrado. El flujo completo es:</p><p>Icnea PMS</p><p>&nbsp; &nbsp; │&nbsp; (nueva reserva / modificación)</p><p>&nbsp; &nbsp; │&nbsp; POST https://app.opland.es/api/icnea/webhook</p><p>&nbsp; &nbsp; ▼</p><p>IcneaWebhookController</p><p>&nbsp; &nbsp; │&nbsp; UPSERT en vacationmarbella_icnea_reservas</p><p>&nbsp; &nbsp; │&nbsp; (unique key: nombre = número de reserva)</p><p>&nbsp; &nbsp; ▼</p><p>PostgreSQL trigger: trg_auto_tarea_limpieza_checkout</p><p>&nbsp; &nbsp; │&nbsp; INSERT/UPDATE en vacationmarbella_tareas_limpieza</p><p>&nbsp; &nbsp; │&nbsp;(unique key: icnea_booking_ref)</p><p>&nbsp; &nbsp; ▼</p><p>Tarea \"Limpieza salida\" creada/actualizada</p><p>Endpoint webhook</p><p><strong>Ruta:</strong>&nbsp;POST /api/icnea/webhook<br><strong>Fichero:</strong>&nbsp;app/Http/Controllers/IcneaWebhookController.php<br><strong>Autenticación:</strong>&nbsp;Ninguna (pública, Icnea no soporta tokens)</p><p>Recibe el XML de Icnea con los datos de la reserva, convierte formatos de fecha (dd/mm/yyyy → yyyy-mm-dd) y realiza un UPSERT en&nbsp;vacationmarbella_icnea_reservas&nbsp;usando&nbsp;nombre&nbsp;(número de reserva) como clave única.</p><p>Re-registro del webhook</p><p><strong>Problema:</strong>&nbsp;Icnea no persiste el webhook indefinidamente. Si no se re-registra periódicamente, Icnea deja de enviar notificaciones.</p><p><strong>Solución:</strong>&nbsp;Re-registro automático cada hora.</p><p><strong>Comando:</strong>&nbsp;php artisan icnea:sync-reservas<br><strong>Fichero:</strong>&nbsp;app/Console/Commands/IcneaSyncReservasCommand.php<br><strong>Frecuencia:</strong>&nbsp;Cada hora (:00)<br><strong>Log:</strong>&nbsp;storage/logs/icnea-sync-reservas.log</p><p>Envía una llamada SOAP&nbsp;ControlActivitat&nbsp;con los datos:</p><ul><li>usr: 1540</li><li>pwd: v<img src=\"data:image/png;base64,\">t<img src=\"data:image/png;base64,\">m<img src=\"data:image/png;base64,\">b</li><li>url:&nbsp;<a href=\"https://app.opland.es/api/icnea/webhook\">https://app.opland.es/api/icnea/webhook</a></li></ul><p>Si Icnea responde&nbsp;&lt;ControlActivitatResult&gt;true&lt;/ControlActivitatResult&gt;, el registro fue exitoso.</p><p><strong>Nota:</strong>&nbsp;El XML se construye por concatenación de strings (no heredoc) para evitar que PHP interpole el carácter&nbsp;$&nbsp;de la contraseña.</p><p>Estado de las reservas en BD</p><p>La tabla&nbsp;vacationmarbella_icnea_reservas&nbsp;contiene&nbsp;<strong>3.198 reservas</strong>&nbsp;provenientes de la migración inicial MySQL→PostgreSQL (Hostinger→OVH), identificables por&nbsp;createdat = 2026-06-05 19:51. Las reservas que lleguen a partir de esa fecha vía webhook tendrán&nbsp;createdat&nbsp;con la fecha real de recepción.</p><p>&nbsp;</p><p>6. Generación automática de tareas de limpieza</p><p>Trigger PostgreSQL</p><p>Cada vez que se inserta o modifica una reserva en&nbsp;vacationmarbella_icnea_reservas, un trigger PostgreSQL genera automáticamente (o actualiza) la tarea de limpieza correspondiente.</p><p><strong>Trigger:</strong>&nbsp;trg_auto_tarea_limpieza_checkout<br><strong>Función:</strong>&nbsp;fn_auto_tarea_limpieza_checkout()<br><strong>Evento:</strong>&nbsp;AFTER INSERT OR UPDATE OF fecha_salida, establecimiento</p><p>Lógica:</p><ol><li>Lee&nbsp;fecha_salida&nbsp;y&nbsp;establecimiento&nbsp;de la reserva.</li><li>Busca el&nbsp;id&nbsp;del inmueble en&nbsp;vacationmarbella_inmuebles&nbsp;cruzando por&nbsp;icnea_lodging_id = establecimiento::integer.</li><li>Si no encuentra el inmueble, no crea tarea (reserva de inmueble no catalogado).</li><li>Hace UPSERT en&nbsp;vacationmarbella_tareas_limpieza:<ul><li>nombre:&nbsp;\'Limpieza salida\'</li><li>id_inmuebles: el id encontrado</li><li>id_tipo: 1 (limpieza)</li><li>fecha_duedate: fecha de checkout</li><li>descripcion:&nbsp;\'Checkout reserva R-XXXXX · Nombre Cliente\'</li><li>icnea_booking_ref: número de reserva (clave de deduplicación)</li></ul></li><li>En caso de conflicto (misma&nbsp;icnea_booking_ref), actualiza&nbsp;fecha_duedate,&nbsp;id_inmuebles,&nbsp;nombre,&nbsp;descripcion&nbsp;y&nbsp;updatedat.</li></ol><p><strong>Estado:</strong>&nbsp;Se ejecutó un backfill sobre las 3.198 reservas existentes, generando&nbsp;<strong>458 tareas de limpieza</strong>&nbsp;(las que tenían&nbsp;fecha_salida&nbsp;no nula e&nbsp;inmueble&nbsp;reconocido).</p><p>&nbsp;</p><p>7. Scheduler — Resumen de tareas programadas</p><p>Fichero:&nbsp;app/Console/Kernel.php</p><figure class=\"table\"><table><thead><tr><th>Comando</th><th>Frecuencia</th><th>Log</th><th>Función</th></tr></thead><tbody><tr><td>icnea:sync</td><td>Diaria 03:00</td><td>logs/icnea-sync.log</td><td>Sincroniza catálogo de inmuebles</td></tr><tr><td>icnea:sync-reservas</td><td>Cada hora</td><td>logs/icnea-sync-reservas.log</td><td>Re-registra webhook en Icnea</td></tr></tbody></table></figure><p>&nbsp;</p><p>Todos los comandos tienen&nbsp;withoutOverlapping()&nbsp;para evitar ejecuciones concurrentes.</p><p>&nbsp;</p><p>8. Corrección de error de login (500)</p><p><strong>Fichero:</strong>&nbsp;app/Http/Helpers/Helper.php&nbsp;(~línea 67)</p><p><strong>Causa:</strong>&nbsp;json_decode&nbsp;del campo&nbsp;menu_personalizado&nbsp;devolvía&nbsp;null&nbsp;para usuarios con ese campo vacío, y el&nbsp;foreach&nbsp;subsiguiente lanzaba un error fatal.</p><p><strong>Solución:</strong>&nbsp;Operador null-coalescing:</p><p>foreach (($menu_personalizado ?? []) as $text_item_menu =&gt; $url_item_menu) {</p><p>&nbsp;</p><p>9. Pendientes y puntos abiertos</p><figure class=\"table\"><table><thead><tr><th>Item</th><th>Estado</th></tr></thead><tbody><tr><td>Confirmar recepción efectiva de webhooks Icnea</td><td>Pendiente — verificar en 48h cuando llegue la próxima reserva/modificación</td></tr><tr><td>Matching manual de 3 inmuebles sin&nbsp;icnea_code</td><td>Pendiente (MARBESA id 63, TORRE BERMEJA id 104, VILLA AVA id 126)</td></tr></tbody></table></figure><p>&nbsp;</p>', NULL, 11, 11, '2026-06-08 12:59:53', '2026-06-08 12:59:53');
