(146, 'Datos usuarios en reporte mensual', '<p>Crear campos DNI y Nombre completo para mostrarlo en el informe mensual del BI.</p>', 2, 2, 3, 3, '2022-09-21', 0.00000000, NULL, NULL, '2022-11-27', '12:25:28', 1, 11, NULL, NULL, NULL, NULL),
