(148, 'Permisos por role de proyecto', '<p>Poder controlar permisos no solo por role principal sino por role de proyecto presente en la tabla usuarios del proyecto</p>', 1, 1, 3, 2, '2022-10-03', 2.00000000, NULL, NULL, '2022-11-27', '15:00:42', 1, 1, NULL, NULL, NULL, NULL),
(149, 'Adaptación Opland a requerimientos Dugarse', NULL, 2, 2, 3, 13, '2022-10-29', 0.00000000, NULL, NULL, '2022-11-27', '21:53:54', 1, 11, NULL, NULL, NULL, NULL),
(150, 'VM Modificaciones Santi', '<p>en renta fija, únicamente renta, inicio y fin<br>cambiar usuarios por empleados<br>jornada por fichaje<br>Menú: Inmuebles, Empleados, Tareas, Tareas mantenimiento, Fichaje, Nominas<br>Nóminas dentro de usuarios<br>Reposiciones no salen en BI<br>Vehículos en BI mostrar Km en lugar de recuento<br>Tareas por Tareas limpieza</p><p>Contrato: indefinido o fijo discontinuo</p>', 2, 2, 3, 3, '2022-11-11', 0.00000000, NULL, NULL, '2022-11-27', '17:03:36', 1, 11, NULL, NULL, 18, NULL),
(151, 'Enviar correo de felicitación de cumpleaños', NULL, 1, 2, 3, 1, '2022-11-20', 2.25000000, NULL, NULL, '2022-11-27', '09:12:37', 1, 11, NULL, 1, NULL, NULL),
(152, 'Incidencia con el envío de correo de pago', NULL, 1, 1, 3, 1, NULL, 2.00000000, NULL, NULL, '2022-11-27', '11:07:49', 1, 11, NULL, 2, NULL, NULL),
