(155, 'Error al cargar nombre de registro relacionado (Imputación-->Tarea)', '<p>NO SE TRATA DE UN ERROR, SINO DE UNA “DISFUNCIÓN”: AL CONSULTAR UNA FICHA DE UN ELEMENTO NO ARCHIVADO QUE TIENE UNA RELACIÓN CON UN ELEMENTO ARCHIVADO DE OTRA TABLA, ESTE NO APARECE EN EL DESPLEGABLE</p><p>Al abrir la imputación <a href=\"https://desarrollos.opland.es/editar/opland/imputaciones/104\">https://desarrollos.opland.es/editar/opland/imputaciones/104</a> no se ve la tarea a la que está asociada, pero sí que se muestra el vínculo Ver; al pulsarlo, me lleva a la tarea correcta.</p><p>Lo mismo sucede si me meto en la pestaña Imputaciones de la tarea: no se muestra nada.</p>', 1, 1, 3, 2, NULL, 0.00000000, 'opland/tareas/FzA4mPsnQ083XR0bjx1LUsYWgRpBotQ4HMUtf3eQ.png', NULL, '2022-11-27', '21:49:50', 1, 11, NULL, NULL, NULL, NULL),
(156, 'Personalización botones de forma de pago', NULL, 1, 2, 3, 1, NULL, 3.00000000, NULL, NULL, '2022-11-28', '10:59:41', 1, 11, NULL, 1, NULL, NULL),
(157, 'Gestion de tablas maestras desde proyecto admin', '<p>Conseguir gestionar todas las tablas maestras desde el propio opland</p>', 1, 2, 3, 2, NULL, 0.00000000, NULL, NULL, '2022-11-28', '09:08:15', 1, 1, 1, NULL, NULL, NULL),
(158, 'Ajustes La Freshquita', NULL, 2, 2, 3, 18, '2023-01-01', 0.00000000, NULL, NULL, '2022-12-03', '19:15:01', 1, 11, NULL, NULL, 17, NULL),
(159, 'Autoregistro', '<p>Se trata de conseguir que cualquier usuario pueda llegar a la página, registrarse y crearse su propio proyecto y modificarlo como él quiera sin que tengamos que intervenir nosotros para nada.</p>', 1, 2, 3, 2, NULL, 0.00000000, NULL, NULL, '2022-12-05', '21:53:09', 1, 1, NULL, NULL, NULL, NULL),
(160, 'Cambio en representación de tablas menú de edición de proyectos versión smartphone vertical', '<p>Si este mismo menú lo ves poniendo el móvil en horizontal se puede ver perfectamente, pero la resolución de la pantalla en vertical no permite dejar tres columnas, tendríamos que mostrar todas las tablas en una columna.</p>', 3, 3, 3, 2, NULL, 0.00000000, NULL, NULL, '2022-12-09', '13:59:23', 1, 2, NULL, NULL, NULL, NULL),
(162, 'Validación y alta de Mejoras Raúl', NULL, 2, 2, 3, 2, NULL, 0.00000000, NULL, NULL, '2022-12-11', '11:31:36', 1, 11, NULL, NULL, NULL, NULL),
(163, 'Diseño de cuadro de mandos de Opland', NULL, 3, 2, 3, 17, '2022-12-31', 12.00000000, NULL, NULL, '2022-12-11', '11:31:03', 1, 2, NULL, NULL, NULL, NULL),
(164, 'Modificación pantalla login desarrollos.opland.es', NULL, 3, 3, 3, 17, '2022-12-09', 2.00000000, NULL, NULL, '2022-12-11', '06:12:00', 1, 2, NULL, NULL, NULL, NULL),
(165, 'Labores administrativas', NULL, 2, 3, 2, 17, NULL, 0.00000000, NULL, NULL, '2022-12-21', '16:02:46', 1, 11, NULL, NULL, NULL, NULL),
(166, 'Nuevo TPV La Freshquita', NULL, 2, 1, 3, 18, NULL, 0.00000000, NULL, NULL, '2022-12-21', '19:15:01', 1, 11, NULL, NULL, 16, NULL),
(167, 'Modificar CM para no tener en cuenta los pagos no archivados de contratos archivados', '<p>en la web ocultamos los pagos (no archivados) de los contratos que se archivan por lo que, si Toni archiva un contrato sin archivar previamente el pago, ya no puede archivarlo. Para evitar hacer un arco de igleasia (dado que este es el comportamiento definido para toda la aplicación), modificamos el cuadro de mandos para que no compute estos pagos como ingresos.</p>', 2, 1, 3, 1, NULL, 0.00000000, NULL, NULL, '2022-12-29', '16:00:20', 1, 11, NULL, NULL, NULL, NULL),
(168, 'Carnicería Gallega: Modificaciones Adri', '<p>MODIFICACIÓN POWER BI</p><ol><li>Problemas con los stocks. Artículo de ejemplo: pechuga de corral y vinos</li><li>Diferenciar ventas por mayor vs tienda ¿cómo se están guardando los albaranes si son todos AT? IdRemoto?</li><li>No están poniendo líneas con descuento por problemas en el precio de última compra.</li><li>Comparar ventas con TPV</li><li>Margen teniendo en cuenta el precio de las últimas dos compras.</li></ol><p>DIAKROS</p><ul><li>No permite el envío a varias direcciones del cliente</li><li>Se cuelga a menudo la impresión de tickets.</li><li>Quitar consetraseña de inicio de Windows</li></ul>', 2, 2, 3, 5, NULL, 0.00000000, NULL, NULL, '2023-01-18', '17:05:13', 1, 11, NULL, NULL, NULL, NULL),
(169, 'Puesta en  marcha OPLAND en Dugarse', NULL, 2, 2, 3, 13, NULL, 0.00000000, NULL, NULL, '2023-01-26', '21:53:34', 1, 11, NULL, NULL, NULL, NULL),
(170, 'LF: Validación de datos La Freshquita (15-feb -->)', NULL, 2, 2, 3, 18, NULL, 0.00000000, NULL, NULL, '2023-02-15', '21:49:50', 1, 11, NULL, NULL, 23, NULL);
INSERT INTO `opland_tareas` (`id`, `nombre`, `comentario`, `id_responsable`, `id_prioridad`, `id_estado`, `id_proyectos`, `fecha_aproximada`, `horas_estimadas`, `file_captura`, `tags_etiquetas`, `createdat`, `updatedat`, `deleted`, `createuser`, `updateuser`, `id_bonos`, `id_facturas`, `id_tipo_tarea`) VALUES
(171, 'DUG: Modificaciones puesta en marcha', '<p>AFECTA A TODA LA APLICACIÓN</p><ol><li>Error en el formato de teléfono en la ficha \"Usuarios\": sólo permite 8 dígitos. {Eliminada la restricción}</li><li>El botón Guardar hace las funciones del Guardar y nuevo cuando se está creando un nuevo registro (si se está editando uno ya existente, funciona correctamente) {Sí, eso es así, ¿Cuál es el error?}</li><li>Quitar \"Mi perfil\" en la pestaña de inicio porque da error 404 {Solucionado el error}</li></ol><p>PROPIO DE DUGARSE</p><ol><li>Tengo que cambiar el nombre de la tabla <i>drn_albaranes </i>por <strong>drn_partes</strong>, lo que afectará a las personalizaciones de campos calculados. {La tabla drn_albaranes ya está creada… he cambiado la personalización para que afecte a drn_partes pero cro que alguna personalización más fallará}</li><li>Tenemos que revisar a quién se le muestra el cuadro de mandos en la pantalla de inicio: sólo debería verlo el rol “gestión”. {Necesitaré que definas a quién quieres que se muestre}</li></ol><p>PERSONALIZACIONES</p><ol><li>En la ficha de <strong>drn_partes</strong>, el campo <i>fecha_albaran </i>debe tener la fecha de hoy como valor por defecto. {Hecho}</li><li>Creo nueva tabla <strong>drn_albaranes </strong>(que realmente son las rutas, es decir, la agrupación de lo que antes eran <i>albaranes </i>y, que por el punto 1, ha pasado a ser <i>partes</i>) → El campo <i>nombre</i> lo mantenemos visible pero autoinformado con la concatenación de <i>“fecha hoy” + \"Ruta de mantenimiento\".</i> Por ejemplo, hoy sería <i>\"20230217 Ruta de mantenimiento\" {Hecho}</i></li><li>En la ficha de “<strong>Fichaje</strong>” los campos <i>nombre </i>y <i>possition </i>deben ocultarse. {Hecho}</li><li>En la tabla <strong>drn_materiales</strong>, el campo <i>nombre</i>, si no se informa, debe tomar el valor del campo <i>id_drn_materiales {Se asigna al seleccionar y si quieren lo pueden cambiar} </i>Redefinido en https://desarrollos.opland.es/ficha/opland/tareas/174</li></ol>', 1, 1, 3, 13, NULL, 0.00000000, NULL, NULL, '2023-02-17', '21:53:09', 1, 11, NULL, NULL, NULL, NULL),
(172, 'Propuesta comercial DRUNI', NULL, 2, 3, 3, 14, NULL, 0.00000000, NULL, NULL, '2023-02-18', '08:42:58', 1, 11, NULL, NULL, NULL, NULL),
(173, 'N&F: reordenar meses en pantalla dashboard y cambiar pantalla de inicio en opland', NULL, 2, 3, 3, 1, '2023-02-21', 0.00000000, NULL, NULL, '2023-02-20', '21:49:50', 1, 11, NULL, NULL, NULL, NULL),
(174, 'DUG: Campo \"Otro\" en materiales y más', '<ol><li>En el formulario drn_albaranes, settear la fecha_albaran=hoy()</li><li>En el formulario de fichaje, ocultar los campos nombre y localización.</li><li>En el formulario de drn_documentos, ocultar el campo nombre.</li><li>La tabla “Materiales” tiene 3 campos para la descripción del material empleado:<ul><li><strong>\"id_drn_materiales\"</strong>: desplegable</li><li><strong>“otro”</strong>: string. <i>[Opcional: Debe mostrarse y ser obligatorio cuando el desplegable “id_drn_materiales” tome el valor “1” (equivalente a “--- (Otro))\"]</i></li><li><strong>“nombre”</strong>: campo <strong>oculto </strong>que debe autoinformarse como:<ul><li>si “otro” no es null, cogerá el valor de Otro</li><li>si “otro” es null, cogerá el valor de la descripción de “id_drn_materiales”</li></ul></li></ul></li></ol><p>&nbsp;</p>', 1, 1, 3, 13, NULL, 0.00000000, NULL, NULL, '2023-02-20', '21:53:09', 1, 11, NULL, NULL, NULL, NULL),
(175, 'VM: Personalizaciones en Fichaje', '<ul><li>En el listado de fichajes, habilitar que el campo Fecha abra el formulario de ficha (el campo nombre lo vamos a ocultar)</li><li>El campo <i>nombre </i>debe ser la concatenación de la fecha, el nombre del usuario y la hora de inicio</li><li>Ocultar en la ficha los campos <i>Localización </i>y <i>Nombre</i></li></ul>', 3, 1, 3, 3, NULL, 0.00000000, NULL, NULL, '2023-02-23', '19:46:32', 1, 11, NULL, NULL, NULL, 2),
(176, 'Opland. Personalizaciones en Facturas y Presupuestos', '<p>En las tablas Facturas y Presupuestos, hacer que el campo Nombre esté oculto y se calcule como CONCAT (num_fact,\" - \",descripcion) y CONCAT (num_ppto,\" - \",descripcion)</p>', 3, 2, 3, 2, '2023-02-27', 0.00000000, NULL, NULL, '2023-02-26', '06:11:22', 1, 2, NULL, NULL, NULL, NULL),
(177, 'NF: No se ocultan en el desplegable de \"contratos\" los grupos archivados', NULL, 1, 2, 3, 1, NULL, 0.00000000, 'opland/tareas/RhddCzO0s8O4hHBd42szFE3JwRIvmFJhpNpuV1GS.png', NULL, '2023-02-27', '21:49:50', 1, 11, NULL, NULL, NULL, NULL),
