(185, 'LF: Tareas 01/may -->', NULL, 2, 2, 3, 18, '2023-06-01', 0.00000000, NULL, NULL, '2023-05-08', '09:05:02', 1, 11, NULL, NULL, 31, NULL),
(186, 'LF: Tareas 01/jun -->', NULL, 2, 3, 3, 18, '2023-07-03', 0.00000000, NULL, NULL, '2023-06-02', '21:49:50', 1, 11, NULL, NULL, 32, NULL),
(187, 'Modificar permisos a roles: ver y editar (case sensitive)', '<p>los campos “puede ver” y “puede editar” son case sensitive</p>', 4, 3, 8, 2, NULL, 0.00000000, NULL, NULL, '2023-07-15', '05:08:28', 1, 125, NULL, NULL, NULL, 2),
(188, 'Me muestra el proyecto opland por defecto', '<p>Sólo debería mostrarme el proyecto que he creado yo, “campamento”</p>', 4, 2, 4, 2, NULL, 0.00000000, 'opland/tareas/xOlxBGabCStbEpO3irYa0UsFaASEh1bM5c5HXCrr.png', NULL, '2023-07-15', '20:01:08', 1, 125, NULL, NULL, NULL, 1),
(189, 'Error: Muestra todos los proyectos al pulsar en \"Mi perfil\"', '<p>Si pulso “Mi perfil” antes de seleccionar un proyecto, se listan todos los proyectos en el menú de la izquierda</p>', 4, 1, 8, 2, NULL, 0.00000000, 'opland/tareas/QAVGoQPt5sEKiV6eCRbT2PGF7zzGyQK8gMl7RWR1.png', NULL, '2023-07-16', '21:00:16', 1, 11, NULL, NULL, NULL, 1),
(190, 'Funcionalidad \"Clonar\"', '<p>Crear un botón en las fichas que permita clonar el registro. Por ejemplo, si quiero duplicar esta tarea para modificar solamente un campo, pulsaría ese botón y me crearía una nueva ficha con la misma info que tengo en pantalla a la espera de que pulse el botón Guardar para grabarlo en bbdd.</p><p>El botón debería mostrarse cuando la ficha está en modo consulta (no editable → <a href=\"https://desarrollos.opland.es/ficha/opland/tareas/190)\">https://desarrollos.opland.es/ficha/opland/tareas/190)</a> para que, al pulsarlo, se abra la ventana en modo edición (<a href=\"https://desarrollos.opland.es/ficha/opland/tareas/190\">https://desarrollos.opland.es/ficha/opland/tareas/190</a>) con los campos informados.</p><p>Adicionalmente, aportaría valor que esto fuera configurable, es decir, podemos crear un campo en la definición de la tabla (<a href=\"https://desarrollos.opland.es/editar_proyecto/opland/opland_tareas\">https://desarrollos.opland.es/editar_proyecto/opland/opland_tareas</a>) para configurar qué campos queremos que se copien en la nueva ficha clonada.</p>', 4, 2, 7, 2, NULL, 0.00000000, 'opland/tareas/en7mLdBM8cbHHBcW9uIzTY2wZ7NSuXDdnngMX4k3.png', NULL, '2023-07-26', '21:29:21', 1, 2, NULL, NULL, NULL, 2),
(191, 'Error al enviar los correos (recuperar contraseña)', '<p>stream_socket_enable_crypto(): Peer certificate CN=`opland.es\' did not match expected CN=`mail.opland.es\' me da esto al enviar los emails, supongo que se ha cambbiado alguna contraseña del correo no?</p>', 1, 1, 6, 2, NULL, 0.00000000, NULL, NULL, '2023-07-26', '11:35:18', 1, 37, NULL, NULL, NULL, 1),
(192, 'Selector (filtro general) se superpone a todo', NULL, 4, 3, 7, 2, NULL, 0.00000000, NULL, NULL, '2023-07-26', '21:31:21', 1, 37, NULL, NULL, NULL, 1),
(193, 'Añadir ruta de la ficha en el encabezado', '<p>Cuando abro una ficha desde el cuadro de mandos (directamente con la url, por ejemplo, <a href=\"https://desarrollos.opland.es/ficha/opland/tareas/192)\">https://desarrollos.opland.es/ficha/opland/tareas/192)</a> tengo que ir al menu lateral para ir al listado (en este caso, al de tareas). Si ponemos en la parte superior de la vista &nbsp;la ruta tipo hipervinculo facilitaría la navegación (por ejemplo, Opland &gt; Tareas, donde pulsar sobre Opland te lleva a la página de inicio y pulsando sobre Tareas vas al listado de tareas)</p>', 4, 3, 7, 2, NULL, 0.00000000, 'opland/tareas/HGgiepaTeX4P7lAu2gG1V9FPXBvDORjkPGiPEfHc.jpg', NULL, '2023-07-27', '21:00:35', 1, 11, NULL, NULL, NULL, 2),
(194, '\"Actualizar varios\" no deben aplicar sobre registros bloqueados', '<p>El campo “bloqued” podemos asimilarlo a una variable de sistema que impide que un registro sea modificado. Esto debería aplicar a todos las funcionalidades que modifican registros, entre ellas, las modificaciones masivas realizadas con el botón “Actualizar Varios”. Dos opciones:</p><p>1.- El proceso no se lleva a cabo y se avisa de que algún registro está bloquado.</p><p>2.- El proceso se ejecuta sin actualizar los bloqueados.</p><p>Yo soy partidario de la primera opción.</p>', 4, 2, 7, 2, NULL, 0.00000000, 'opland/tareas/FAqFO0Ni5synoEm9RBhktUYtKECNpUqUTbq7amJ2.png', NULL, '2023-07-30', '06:32:33', 1, 11, 11, NULL, NULL, 2),
(195, 'Mantener cabecera de ficha fija cuando se usa el scroll', '<p>Cuando una ficha tiene muchos campos y es necesario utilizar el scroll vertical, la cabecera debe permanecer visible.</p>', 4, 3, 4, 2, NULL, 0.00000000, NULL, NULL, '2023-08-01', '11:02:48', 1, 11, NULL, NULL, NULL, 2),
(196, 'VM: Formación Nerea', NULL, 2, 3, 3, 3, NULL, 0.00000000, NULL, NULL, '2023-08-02', '17:48:22', 1, 11, NULL, NULL, NULL, NULL),
(197, 'Corregir la regla que muestra las tablas del proyecto seleccionado', '<p>Actualmente se muestran las tablas que comienzan por el mismo nombre, pero, en caso de proyectos con nombres similares, se muestran las de ambos proyectos. Adjunto pantallazo de lo que veo en el proyecto “mareny” (existe otro que se llama “marenyblau”).</p>', 1, 1, 5, 2, NULL, 0.00000000, 'opland/tareas/RODEhsSptwe1XimYflV6efC42gEIkR1jgxy8S6Nt.png', NULL, '2023-08-05', '05:24:05', 1, 11, NULL, NULL, NULL, 1),
(198, 'Campo bloqued \"sigue mostrando editar de ficha\"', NULL, 4, 2, 7, 2, NULL, 0.00000000, NULL, NULL, '2023-08-08', '21:32:11', 1, 37, NULL, NULL, NULL, NULL),
(199, 'Tareas ago\'23 - semana 2: Tareas backoffice', NULL, 2, 1, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-08-09', '06:41:53', 1, 11, NULL, NULL, 35, NULL),
(200, 'Tareas ago\'23 - semana 3: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-08-22', '06:45:50', 1, 11, NULL, NULL, 36, NULL),
(201, 'Auto registro en proyectos mediante un código', NULL, 4, 1, 3, 2, NULL, 0.00000000, NULL, NULL, '2023-08-24', '16:36:19', 1, 37, NULL, NULL, NULL, NULL),
(202, 'Inclusión de filtros en listados secundarios', '<p>CONTEXTO</p><p>Cuando abrimos una ficha de una tabla “A” con una relación 1-n con otra tabla “B”, se muestra, en la pestaña de la tabla “B”, dos listados:</p><p>1.- Un primer listado con todos los registros de la tabla “B” vinculados con el registro de la ficha abierta.</p><p>2.- Un segundo listado con todos los elementos de la tabla “B” que no tienen relacionado ningún registro de la tabla “A”.</p><p>Sobre estos dos listados no se puede ejercer ninguna acción del tipo ordenar (pinchando sobre el encabezado) o hacer una búsqueda (con filtros).</p><p>&nbsp;</p><p>SE SOLICITA</p><p>Para el segundo listado, descartada técnicamente en su día la opción de poder ordenar por el encabezado, habilitar la búsqueda por filtro, ya que actualmente sólo se muestran los primeros 50 registros de la tabla “B”.</p><p>EJEMPLO PRÁCTICO</p><p>Para hacer la conciliación bancaria del Mareny, tengo que relacionar un movimiento de la cuenta con varios gastos de la tabla Gastos. Como hay muchos gastos pendientes de conciliar a final de mes, me cuesta mucho buscárlos (y al final hago el ejercicio contrario: abrir el gasto y asociarle el movimiento bancario, uno a uno).</p>', 1, 1, 5, 2, NULL, 0.00000000, 'opland/tareas/KCsZfXAjNIWnrN07R4gO5iZ5yHnGMew81F6Jq9ys.png', NULL, '2023-08-29', '16:48:59', 1, 2, NULL, NULL, NULL, 2),
(203, 'MB: Personalización asistentes y delegaciones en asambleas', '<p>PTE DEFINIR</p>', 2, 1, 5, 20, NULL, 0.00000000, NULL, NULL, '2023-08-29', '15:39:46', 1, 2, NULL, NULL, NULL, 2),
(204, 'Registro fallo responsive (se montan logos)', NULL, 4, 2, 3, 2, NULL, 0.00000000, 'opland/tareas/Orpa5AknxcYejopQUBLpHGpxnJMrR73wxaCpjSlL.jpg', NULL, '2023-08-29', '12:02:37', 1, 37, NULL, NULL, NULL, NULL),
(205, 'Tareas ago\'23 - semana 4: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-08-22', '06:26:55', 1, 11, NULL, NULL, 39, NULL),
(206, 'Comprobar correo existe en usuario en el registro por invitacion', '<p>No he comprobado si el usuario existe a la hora de crear el usuario</p>', 4, 1, 3, 2, NULL, 0.00000000, NULL, NULL, '2023-08-30', '12:16:54', 1, 37, NULL, NULL, NULL, NULL),
(207, 'Cuadros de mandos en menu lateral', '<p>Ahora mismo al subir el codigo ha desaparecido como tal la pantalla de inicio como antes, entonces no se ve los cuadros de mando, tomas propone ponerlo en el menu lateral para que no lo pongamos en el menu de inicio y asi no relentiza, al ponerlo ahi se puede poner como pantalla de inicio y luego en caso de no tenerlo que te lleve a la pantalla y que te de infomacion del servicio y algo para contratarlo, en plan formulario</p>', 1, 2, 7, 2, NULL, 0.00000000, NULL, NULL, '2023-08-30', '05:39:52', 1, 37, 11, NULL, NULL, NULL),
(208, 'Quitar email bienvenida', NULL, 4, 1, 7, 2, NULL, 0.00000000, NULL, NULL, '2023-08-31', '05:37:31', 1, 37, 11, NULL, NULL, NULL),
(209, 'Pagina inicio marcado por la tabla rol', NULL, 4, 1, 7, 2, NULL, 0.00000000, NULL, NULL, '2023-09-01', '05:36:33', 1, 37, 11, NULL, NULL, NULL),
(210, 'Revisión permisos edición', '<p>Sólo debería poder crear registros sobre tablas en las que tengo permiso de edición.</p><p>Sin embargo, cuando entro en una tabla a través de una pestaña de una ficha, esto no se está validando, permitiéndome dar de alta un registro donde sólo tengo permiso de consulta.</p><p>EJEMPLO: Proyecto Mareny Blau en DESA</p><p>Login con usuario 141 - María Luisa Cárcel</p><p>Rol: socio, que puede editar únicamente la ficha “Propietario”.</p><p>La tabla “Propietario” está relacionada con “Vivienda_propietario”, por lo tanto, en la ficha de “Propietario” aparece una pestaña en la que puedo ver los registros de “vivienda_propietario”.</p><p>Pero… también aparece el botón “Crear vivienda_propietario”, cosa a la que no tiene acceso este rol.</p><p>&nbsp;</p><p>Adjunto pantallazo.</p><p>&nbsp;</p>', 4, 1, 7, 2, NULL, 0.00000000, 'opland/tareas/atvTRprWdLRuIZkqGbvaGdnpy2bi498UQ0L97qMA.png', NULL, '2023-09-01', '06:04:43', 1, 2, 11, NULL, NULL, 1),
(211, 'Añadir campos en Perfil y dar opción de volver al \"Panel\"', '<p>Cuando selecciono en el menú superior derecho la opción “Perfil”, me lleva a una pantalla en la que me solicita datos para una nueva contraseña. Aquí añadiría los campos “Nombre” y “Mail (usuario)”.</p><p>Adjunto pantallazo.</p><p>Aparte de esto, una vez en esta pantalla, no tengo forma de volver a la pantalla de trabajo (al Panel). Me veo obligado a salir del proyecto y volver a entrar.</p><p>&nbsp;</p><p>&nbsp;</p>', 4, 3, 8, 2, NULL, 0.00000000, 'opland/tareas/jdlNy1xTaPgKpOp49T4HpmOgWZbqOWoqeWMNSYUf.png', NULL, '2023-09-01', '05:52:58', 1, 2, 11, NULL, NULL, 2),
(212, 'Crear acceso directo a una URL en el menú lateral', '<p>Describe Dopi</p><p>Funcioalidad: Dar acceso a un cuadro de mandos o a una ficha directamente (hemos visto el caso de un propietario de Mareny)</p><p>Parte uno hacer una vista donde por url se pueda ver un cuadro de mandos - Hecho</p><p>Parte dos, poder crear enlaces personalizados de menú mendiant “nombre\":\"Destino\". Yo haría a nivel de rol poder introducir un nuevo campo que fuera menu_personalizado en formato json {\"nombre1\":\"destino1\",\"nombre2\":\"destino2\"} y a partir de ahí montar en el menú de la inzquierda la entrada nombre1 que te lleve a la url destino1 y así sucesivamente.</p>', 4, 1, 3, 2, NULL, 0.00000000, 'opland/tareas/jdlNy1xTaPgKpOp49T4HpmOgWZbqOWoqeWMNSYUf.png', NULL, '2023-09-01', '10:38:29', 1, 2, NULL, NULL, NULL, 2),
(213, 'Formulario para alta de usuarios por código', '<p>Además de crear el usuario, lo realmente útil es que sea el propio usuario quien complete ciertos datos. Para introducir esos datos, propongo crear por defecto una tabla nueva llamada “ Formulario” donde, a la vez que se crea el usuario, se cree un registro con su nombre, mail y su control_user. El admin podrá añadir en esta tabla tantos campos como quiera. Añadir dos botones en el listado de “Formulario” con el texto “Aprobar” y “Rechazar”.</p>', 4, 2, 4, 2, NULL, 0.00000000, NULL, NULL, '2023-09-01', '16:32:22', 1, 11, NULL, NULL, NULL, 2),
(214, 'Clonación de registros', '<p>La clonación funciona correctamente, pero debería setear los campos createuser y createdate con los valores reales, no clonar los del registro clonado.</p>', 4, 2, 7, 2, NULL, 0.00000000, NULL, NULL, '2023-09-16', '20:56:44', 1, 11, NULL, NULL, NULL, NULL),
(215, 'Visita comercial GreenB2E', NULL, 2, 3, 3, 21, '2023-09-20', 0.00000000, NULL, NULL, '2023-09-20', '08:29:55', 1, 11, 11, NULL, NULL, NULL),
(216, 'Icono retorno a menú inicial', '<p>&nbsp;en la vista móvil ha desaparecido el logo de la empresa &nbsp;que, pinchando sobre él, te llevaba al menú principal</p>', 4, 1, 7, 2, NULL, 0.00000000, 'opland/tareas/lCoTjsZDr1zPpOyf9KNbWu9FHbBU9NmooIWVWx9a.jpg', NULL, '2023-09-22', '20:55:27', 1, 11, NULL, NULL, NULL, NULL),
(217, 'Botón Guardar y continuar', '<p>Actualmente, este botón <strong>Guardar y continuar</strong> graba la información introducida hasta &nbsp;el momento y te mantiene en la misma pantalla, pero en modo no editadle (lo mismo que hace el botón <strong>Guardar</strong>). Mi propuesta es que haga lo mismo, pero &nbsp;mantenido la pantalla en modo editadle.</p>', 4, 2, 7, 2, NULL, 0.00000000, NULL, NULL, '2023-09-24', '20:57:37', 1, 11, NULL, NULL, NULL, 2),
(218, 'Vínculo “ver” en campos tipo fichero', '<p>&nbsp;Tenemos un tipo de campo “fichero” que:</p><ol><li>Permite subir tantos ficheros como se seleccionen en la ventana emergente tipo explotador de Windows.</li><li>Una vez subidos, no permite borrarlos.</li><li>Para consultar los ficheros subidos, muestra en la parte inferior de este campo:<ul><li>tantas miniaturas como imágenes subidas.</li><li>tratos vínculos “ver” como resto de ficheros no imagen subidos.</li></ul></li></ol><p>¿Cómo debería ser?</p><ol><li>Sólo debe permitir un único fichero.</li><li>Debe tener un aspa o algo similar que permita eliminar el fichero subido.</li><li>Una vez subido un fichero, el campo debería mostrarse como no editable (en cuanto al texto), con el nombre del fichero subido (esto obligaría a cambiar la lógica actual que le da el nombre al fichero guardado) y el aspa mencionada en el punto 2.</li></ol>', 4, 1, 7, 2, NULL, 0.00000000, 'opland/tareas/MeaNRmzmp3b9eINsRJ26XoMktt2gTnlqH9uIaSyr.png', NULL, '2023-09-24', '20:54:05', 1, 11, NULL, NULL, NULL, 2),
(219, 'Ocultar/mostrar campos en ficha según el rol', '<p>¿Sería posible, en la definición de los campos de una tabla, añadir un texto para especificar qué roles pueden ver ese campo?</p>', 4, 1, 4, 2, NULL, 0.00000000, 'opland/tareas/MeaNRmzmp3b9eINsRJ26XoMktt2gTnlqH9uIaSyr.png', NULL, '2023-09-24', '12:51:35', 1, 11, NULL, NULL, NULL, 3),
(223, 'Aviso al cambiar el tipo de campo en una tabla', '<p>Si un usuario intenta cambiar el tipo de campo, es probable que acabe generando un fallo en la plataforma. Por ejemplo, si tenemos un campo de texto y hemos metido ya varias entradas y cambiamos el tipo a “desplegable”, se genera un error. Igualmente, si tenemos un campo fecha y lo pasamos a campo moneda, se genera un error por valor numérico fuera de rango.&nbsp;</p><p>Lo suyo sería encontrar la forma de que el usuario no pueda “romper el juguete”, no sé si no permitiendo cambiar el tipo una vez creado o buscando las entradas existentes, y si no son compatibles con el tipo nuevo seleccionado, que el cambio no se lleve a cabo y salga un aviso (no sé si todo esto es posible, perdón).</p>', 4, 2, 3, 2, NULL, 0.00000000, 'opland/tareas/05VyPy5Z37JkIiDZSwrljWtsotp0JgFXwr4Sl2xH.jpg', NULL, '2023-10-04', '09:18:42', 1, 2, NULL, NULL, NULL, 3),
(224, 'Aviso al crear tabla sin nombre', '<p>Ahora mismo, cuando intentamos crear una nueva tabla sin nombre, nos sale un syntax error((adjunto). Deberíamos hacer lo mismo que cuando intentamos crear un nuevo proyecto, avisar de que se tiene que incluir un nombre y no ejecutar la acción.</p>', 4, 2, 7, 2, NULL, 0.00000000, 'opland/tareas/mE9vDwTkIULXZBFZHJE6NLh4nqkFMdemY4zowCoj.jpg', NULL, '2023-10-04', '05:52:05', 1, 2, 11, NULL, NULL, 3),
(225, 'Campos booleanos Sí/No', '<p>Hasta ahora los campos booleanos se están mostrando como checkbox, de manera que si no está marcado es un 0 y si está marcado es un 1.</p><p>Adicionalmente necesitamos un campo Sí/No que sea un desplegable ¿de que manera se podría hacer? ¿es excluyente o podemos mantener ambos tipos de visualizaciones?</p>', 4, 2, 7, 2, NULL, 0.00000000, 'opland/tareas/LOV7PODgElQ0Wc12U9qgRVE29dv2xNAuYSHTH4Fo.png', NULL, '2023-10-05', '05:47:37', 1, 11, 11, NULL, NULL, 2),
(226, 'Error al clonar factura', '<p>&nbsp;Error al intentar clonar elementos de esta tabla: https://desarrollos.opland.es/ficha/opland/facturas/36<br>Pista: en la tabla \"Facturas\", el campo Nombre es calculado, de manera que, al modificar el campo \"descripcion\" se actualiza, concatenando \"num_fact\" y \"descripcion\" ¿podría ser la causa?</p>', 4, 2, 7, 2, NULL, 0.00000000, NULL, NULL, '2023-10-07', '05:34:02', 1, 11, 11, NULL, NULL, 1),
(227, 'Tareas sept\'23 - semana 1: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-08-22', '06:04:10', 1, 11, NULL, NULL, 45, NULL),
(228, 'Tareas sept\'23 - semana 2: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-08-22', '06:04:28', 1, 11, NULL, NULL, 46, NULL),
(229, 'Tareas sept\'23 - semana 3: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-08-22', '06:04:44', 1, 11, NULL, NULL, 47, NULL),
(230, 'Tareas sept\'23 - semana 4: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-08-22', '06:05:00', 1, 11, NULL, NULL, 48, NULL),
(231, 'Tareas oct\'23 - semana 1: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-08-22', '06:05:22', 1, 11, NULL, NULL, 49, NULL),
(232, 'Tareas ago\'23 - semana 5: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-08-22', '07:26:00', 1, 11, NULL, NULL, 43, NULL),
(233, 'Filtros en la vista “Archivados”', '<p>Cuando consultas los registros archivados (deleted =1) desde el listado que hace las veces de buscador, los filtros no funcionan; en concreto, te devuelven a la vista de los no archivados.</p>', 4, 1, 7, 2, NULL, 0.00000000, NULL, NULL, '2023-10-08', '20:52:46', 1, 11, NULL, NULL, NULL, NULL),
(234, 'Tareas oct\'23 - semana 3: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-08-22', '06:23:47', 1, 11, NULL, NULL, 61, NULL),
(235, 'Eliminar error si el usuario crea Rol y después Usuarios', '<p>Si un usuario crea un proyecto desde cero, al crear Rol y luego Usuarios, salta el error adjunto diciendo que la vista Usuarios ya existe. ¿Es posible que tanto si creas Rol como si creas Usuarios se crea la correspondiente pero por error al crear Rol no apareceUsuarios y al crear Usuarios sí aparece Rol? Si después de llegar al error vuelvo atrás, aparece la tabla Usuarios, por lo que tiene pinta de ser así.</p>', 4, 2, 3, 2, NULL, 0.00000000, 'opland/tareas/oiCscWVgq91QqxkOyq013zqIyZ49ur1GUtTAxhxB.png', NULL, '2023-10-10', '20:12:30', 1, 2, NULL, NULL, NULL, 3),
(236, 'Ajustar cuadro de mandos', '<p>Dejo a continuación los cambios que he hecho para que quede lo más grande posible sin encabezados, sin barras de scroll y sin márgenes innecesarios. Los cambios los indico en cursiva y negrita.</p><p>Me gustaría hacer la card más grande como indico en la imagen adjunta pero si eso supone ver la barra de scroll de la web creo que no vale la pena. Lo que veas.</p><p>--------------------------------------------------------------------------------------</p><p><strong>Cambio 1: Quitar margen inferior de la “card”</strong></p><p>&lt;div class=\"card\"&gt;</p><p>[bootstrap-e…ed.css:1053</p><p>.card {</p><p>&nbsp; &nbsp; /* margin-bottom: 2rem; */ <i><strong>(tachar)</strong></i></p><p>&nbsp; &nbsp; box-shadow: 0 4px 24px 0&nbsp;rgba(34, 41, 47, 0.1);</p><p>&nbsp; &nbsp; transition: all 0.3s&nbsp;ease-in-out, background 0s, color 0s, border-color 0s;]</p><p>&nbsp;</p><p><strong>Cambio 2: Borrado de elemento completo.</strong></p><p>&lt;div class=\"content-header row\"&gt;</p><p>&nbsp;&lt;div class=\"content-header-left col-12 mb-2\"&gt;</p><p>&nbsp; &lt;h3 class=\"content-header-title float-left mb-0\" style=\"width: fit-content;\"&gt; Cuadro de mandos &lt;/h3&gt;</p><p>&nbsp;&lt;/div&gt;</p><p>&lt;/div&gt;</p><p><i><strong>(eliminar todo el elemento)</strong></i></p><p><strong>Cambio 3: Modificar márgenes, quitar texto y redimensionar iframe y contenedor embebido.</strong></p><p>&lt;table style=\"font-family: \'Montserrat\',Arial,sans-serif;width: 90%;margin: auto;margin-top: <i><strong>30px</strong></i>;margin-bottom: 50px <i><strong>(tachar)</strong></i>;\" cellpadding=\"0\" cellspacing=\"0\" role=\"presentation\"&gt;</p><p>&nbsp;&lt;tbody&gt;</p><p>&nbsp;&lt;tr&gt;</p><p>&nbsp;&nbsp;&lt;td class=\"sm-px-24\" style=\"\"&gt;</p><p>&nbsp; &nbsp;&lt;p class=\"sm-leading-32\" style=\"font-weight: 600; font-size: 20px; margin: 0 0 24px <i><strong>(tachar)</strong></i>; --text-opacity: 1; color: #263238; color: rgba(38, 50, 56, var(--text-opacity));\"&gt;</p><p>&nbsp; &nbsp; “ GreenB2E “ <i><strong>(eliminar)</strong></i></p><p>&nbsp; &nbsp; &nbsp;&lt;iframe src=\"/pbi?_token=wSjV8LjuOf97y9nUujTdZgo2z5WrOPrLhOdrlt7e\" alt=\"GreenB2E\" style=\"width: 100%; height: <i><strong>765px</strong></i>;\"&gt;</p><p>&nbsp; &nbsp; &nbsp; #document</p><p>&nbsp; &nbsp; &nbsp; &nbsp;&lt;html&gt;</p><p>&nbsp; &nbsp; &nbsp; &nbsp; &lt;head&gt; …..&lt;/head&gt;</p><p>&nbsp; &nbsp; &nbsp; &nbsp; &lt;body&gt;</p><p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&lt;div id=\"embedContainer\" name=\"embedContainer\" style=\"width: 100%; height:<i><strong>745px</strong></i>;\"&gt;&lt;iframe src=\"https://app.powerbi.com/reportEmbed?reportId=ffb170cd-c12a-4d49-a46a-e1f3a77c192f&amp;amp;uid=k3db8w\" scrolling=\"no\" allowfullscreen=\"true\" style=\"width: 100%; height: 100%;\"&gt;&lt;/iframe&gt;&lt;/div&gt;</p>', 4, 2, 3, 2, NULL, 0.00000000, 'opland/tareas/dbmpwduMpeiy6pijClG8txAgyJ5PEbugia6zpVIS.jpg', NULL, '2023-10-10', '17:23:59', 1, 2, NULL, NULL, NULL, 3),
(237, 'Revisar permisos para acceso a cuadros de mandos', '<p>El menú lateral “Cuadro mandos” debería ser sólo accesible para los roles que tenga “Cuadro mandos” en el campo “Puede ver”.</p><p>Analizar por qué en Marenyblau sólo es accesible para el rol admin.</p>', 4, 1, 6, 2, NULL, 0.00000000, NULL, NULL, '2023-10-19', '14:20:07', 1, 11, NULL, NULL, NULL, NULL),
(238, 'Cuadro de mandos quitar todos los margenes posibles', NULL, 4, 3, 3, 2, NULL, 0.00000000, NULL, NULL, '2023-10-27', '08:34:39', 1, 37, NULL, NULL, NULL, NULL),
(239, 'Implantación, migración y cuadro de mandos', NULL, 2, 2, 3, 21, NULL, 0.00000000, NULL, NULL, '2023-10-29', '22:57:39', 1, 11, NULL, NULL, NULL, NULL),
(240, 'Revisión con Fátima', '<ol><li>Añadir icono en Seguros → Hecho</li><li>Escrituras: Buscar en filtros → Hacho</li><li>Firmas: ¿se puede subir el fichero .pfx? Añadir icono → Descartado</li><li>Sociedad y proveedor en Mayusculas y conceptos la primera en mayúscula → Hecho</li><li>Gastos recurrentes → Nuevo requerimiento a presupuestar tras finalización de puesta en marcha.</li><li>Revisar automatización de campo nombre → Hecho</li></ol>', 2, 2, 3, 21, '2023-11-27', 0.00000000, NULL, NULL, '2023-10-31', '11:36:22', 1, 11, NULL, NULL, NULL, NULL),
(241, 'Al archivar se borra relación con otra tabla', '<p>Al archivar un registro se elimina su relación con otra tabla. Pongo un ejemplo:</p><p>Proyecto: Mareny Blau</p><p>Tablas: Gastos y Cuenta_9240</p><p>Relación: gastos.id_cuenta_9240</p><p>Incidencia: cuando se archiva un gasto asociado a un movimiento de Cuenta_9240, se borra el valor de gastos.id_cuenta_9240</p><p>Ejemplo para probar:</p><p>&gt; Gasto: https://desarrollos.opland.es/ficha/marenyblau/gastos/1678</p><p>&gt; Movimiento asociado: https://desarrollos.opland.es/ficha/marenyblau/cuenta_9240/6257</p>', 4, 1, 4, 2, NULL, 0.00000000, NULL, NULL, '2023-11-02', '19:16:20', 1, 11, NULL, NULL, NULL, 1),
(242, 'Corregir los errores al modificar datos sección \"Perfil\"', '<p>Al entrar en la sección perfil e ir a modificar Nombre y Correo electrónico aparecen los errores “El campo contraseña actual es obligatorio”, “El campo new password es obligatorio”, “El campo new confirm password es obligatorio”.</p><p>No se puede evitar el error hagas lo que hagas. Entiendo que debería dejar modificar los campos Nombre y Email, al margen de que cambies la contraseña o no.</p><p>De paso podríamos modificar los mensajes de error.</p>', 4, 2, 6, 2, NULL, 0.00000000, 'opland/tareas/sfimbaTaKQMxo7OusGQFq4OCcZw3VTWCBbAbtICn.png', NULL, '2023-11-02', '20:48:11', 1, 18, NULL, NULL, NULL, 1),
(243, 'Cambio de aspecto de cursor al pasar sobre la X en una ventana emergente (ver en textos largos)', '<p>Ahora mismo el cursor que aparece al pasar sobre la X para cerrar una ventana emergente es el que se utiliza siempre para modificar texto, debería aparecer la mano que indica que se puede clicar para cerrar la ventana.</p>', 1, 3, 5, 2, NULL, 0.00000000, NULL, NULL, '2023-11-02', '19:13:11', 1, 18, NULL, NULL, NULL, 3),
(245, 'Autocalcular campo \"nombre\" y ocultarlo', '<p>En las tablas “firma_digital” y “cuentas_anuales” ocultar el campo “nombre”, autocalculándolo:</p><ul><li>Firmas → [fecha_caducidad].Año &amp; “.” [fecha_caducidad].Mes &amp; “ ” &amp; [sociedad]</li><li>Cuentas → [ejercicio] &amp; “_” &amp; [sociedad]</li></ul>', 3, 1, 3, 21, '2023-11-09', 0.00000000, NULL, NULL, '2023-11-07', '19:43:31', 1, 11, NULL, NULL, NULL, 2),
(246, 'Bloquear contenidos en VM', '<p>Santi solicita que los usuarios no puedan alterar la información de los registros en ciertas circunstancias, pero que alguien de la organización sí que pueda hacerlo. Para ello propongo:</p><p>Un proceso (script) que se lance a las 00:00 y que ponga el campo deleted o blocked a 1 en:</p><ol><li>Todo los fichajes</li><li>&nbsp;Las tareas de mantenimiento y limpieza que tengan el campo duración informando.</li></ol><p>La decisión de si se setea el campo deleted o block depende de si podemos restringir por riles el acceso al listado de archivados. Si no es posible, entonces haríamos visible por código el campo blocked para los roles que nos digan.</p>', 1, 1, 6, 3, NULL, 0.00000000, NULL, NULL, '2023-11-08', '22:02:53', 1, 11, NULL, NULL, NULL, NULL),
(247, 'Creación de manual de la plataforma', NULL, 3, 3, 2, 2, NULL, 0.00000000, NULL, NULL, '2023-11-09', '07:53:34', 1, 2, NULL, NULL, NULL, 3),
(248, 'Tamaño de campo \"Valor\" en tabla \"Configuracion\" y evitar el error cuando un usuario intenta meter más caracteres que los configurados en el campo', '<p>En la actualidad, la tabla “Configuracion” se crea con un campo \"Valor\" de 32 caracteres. El problema es que en campos como submenu, es normal meter muchos nombres de tabla y superar los 32 caracteres, generando un error.</p><p>Propongo por un lado aumentar a 64 caracteres “Valor” en “Configuracion” y por otro, que se muestre un error que le diga al usuario que amplíe el tamaño de “Valor” para que no aparezca el error que aparece ahora y que es lo que tenemos que intentar evitar.</p>', 1, 2, 5, 2, NULL, 0.00000000, 'opland/tareas/k2tlvmlPffPT8mmZDaIEX0M9bGshGhaX6Y8WlzEt.jpg', NULL, '2023-11-12', '18:59:06', 1, 2, NULL, NULL, NULL, 3),
(249, 'Mostrar el nombre de proyecto tal y como lo pone el usuario', '<p>Ahora mismo cuando pones el proyecto con un espacio te lo junta todo, me parece bien para la BD pero no para la interfaz. ¿Se puede solucionar?</p><p>¿Se puede poner un nombre de proyecto con espacios que luego se guarde en base de datos con guiones bajos? Eso es algo básico para UX.</p>', 1, 2, 5, 2, NULL, 0.00000000, NULL, NULL, '2023-11-12', '18:58:30', 1, 2, NULL, NULL, NULL, 3),
(250, 'No permite borrar el fichero cargado', '<p>Estoy intentando borrar la imagen subida y no puedo hacerlo. Voy a borrarla por por BD, pero es algo que me ha pasado también en otra tarea.</p>', 4, 2, 3, 2, NULL, 0.00000000, NULL, NULL, '2023-11-12', '14:08:40', 1, 2, 1, NULL, NULL, 3),
(251, 'Tareas oct\'23 - semana 2: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-11-15', '06:23:31', 1, 11, NULL, NULL, 60, NULL),
(252, 'Tareas oct\'23 - semana 4: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-11-15', '06:27:09', 1, 11, NULL, NULL, 62, NULL),
(253, 'Tareas oct\'23 - semana 5: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-11-15', '06:27:28', 1, 11, NULL, NULL, 67, NULL),
(254, 'Tareas nov\'23 - semana 1: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-11-15', '06:25:10', 1, 11, NULL, NULL, 68, NULL),
(255, 'Tareas nov\'23 - semana 2: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-11-15', '06:28:05', 1, 11, NULL, NULL, 68, NULL),
(256, 'Tareas nov\'23 - semana 3: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-11-15', '07:46:03', 1, 11, NULL, NULL, 70, NULL),
(257, 'Revisión con Fátima', '<ol><li>Pte punto 2 reunión anterior → Hecho✅</li><li>CM-Facturas recibidas: fechas mal introducidas (año 0023):<ol><li>Corregir masivamente → Hecho✅</li><li>¿Por qué no aparece en BI? 🟡</li></ol></li><li>Opland facturas:<ol><li>Usamos ficha para facturas con un sólo tipo de IVA. Metemos el porcentaje y se autocalculará el importe. → Hecho en PowerBI ✅</li><li>Para más de un tipo de IVA, se usará la pestaña fra_IVA. → Hecho en PowerBI ✅</li><li>En fase II se autocalcularán los importes de IVA, Retención y Total factura.🟡</li></ol></li><li>¿Podemos meter alguna configuración en los campos fecha para que, si se escribe año 23, se autocorrija a 2023? 🟡</li><li>Ver excel importación y descubrir empresa real asociada a las cuentas y firmas con sociedad de nombre extralargo. 🟠 Revisar con Fátima porque ha modificado los nombres y hay algunos repetidos.</li><li>CM-Avales:<ol><li>En todos los cuadros, siempre proyecto y sociedad. ✅</li></ol></li><li>En avales_doc ¿puedo hacer que file sea obligatorio? 🟠</li><li>CM-Polizas (listado y detalle aval): colores ✅<ol><li>Vigente: verde</li><li>Cancelado: gris</li><li>Resto: naranja</li></ol></li><li>Importe: poner la prima no canceladas ✅</li><li>Tipos de gasto (facturas recibidas): añadir desplegable con los tipo de la foto. ✅</li></ol>', 2, 2, 6, 21, NULL, 0.00000000, NULL, NULL, '2023-11-23', '09:20:20', 1, 2, NULL, NULL, NULL, NULL),
(258, 'Reunión con VM: Araceli y Javier (formación)', NULL, 2, 2, 2, 3, NULL, 0.00000000, NULL, NULL, '2023-11-30', '16:37:15', 1, 11, NULL, NULL, NULL, NULL),
(259, 'Gestión de error con ficheros obligatorios', '<p>Cuando marcamos que un campo “fichero” es obligatorio, si el usuario no lo incluye, se muestra la típica pantalla de error de Opland ¿podemos mostrar un mensaje de error como hacemos en el resto de campos obligatorios?</p><p>Prime: además de mostrar el texto rojo debajo del campo ¿podríamos desplegar un pop-up?</p>', 1, 1, 6, 21, NULL, 0.00000000, NULL, NULL, '2023-12-05', '15:53:08', 1, 11, NULL, NULL, NULL, 2),
(260, 'Tareas nov\'23 - semana 4: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-12-14', '06:10:06', 1, 11, NULL, NULL, 71, NULL),
(261, 'Tareas dic\'23 - semana 1: Tareas backoffice', NULL, 2, 3, 3, 19, NULL, 0.00000000, NULL, NULL, '2023-12-14', '06:10:30', 1, 11, NULL, NULL, 72, NULL),
